INSERT OR IGNORE INTO chapter (id,tier,chapter_no,title,description,`order`,status,createdAt,updatedAt) VALUES ('06-stars-luong-thuong',1,6,'S.T.A.R.S - MÔ HÌNH LƯƠNG THƯỞNG','Mo hinh luong thuong S.T.A.R.S',6,'draft','2026-06-20T11:02:27Z','2026-06-20T11:02:27Z');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('33a50907-47c8-47f7-af7c-601ff1920332','06-stars-luong-thuong',NULL,1,'6.1 ĐỊNH VỊ MÔ HÌNH','61-inh-vi-mo-hinh',0,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('46063ee0-4653-4eb1-b110-dad96c9545c5','06-stars-luong-thuong','33a50907-47c8-47f7-af7c-601ff1920332',2,'Tại sao lại là S.T.A.R.S','tai-sao-lai-la-stars',1,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2a314772-8ac7-4139-8072-cdb9ac9d907b','46063ee0-4653-4eb1-b110-dad96c9545c5',0,'text','Roadmap là bản đồ để chúng ta biến tổ chức thành một bầu trời. S.T.A.R.S là bộ tiêu chuẩn giúp mỗi thành viên trở thành một ngôi sao thật sự, đủ sáng, đủ trong và đủ vững để cùng nhau làm nên một bầu trời ấy.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d8707178-a890-4012-948b-681e3aa9ae5a','46063ee0-4653-4eb1-b110-dad96c9545c5',1,'text','**“Một tổ chức lớn không được xây bằng những con người làm công, mà bằng những ngôi sao biết tỏa sáng đúng quỹ đạo của mình.”**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('25473fa3-280e-4fc3-8a56-9e360291effe','46063ee0-4653-4eb1-b110-dad96c9545c5',2,'text','Trong một bầu trời thật, ngôi sao không chỉ tồn tại để phát sáng cho riêng nó, mà còn góp phần tạo nên trật tự của cả chòm sao. Trong một tổ chức cũng vậy, mỗi con người chỉ thực sự có giá trị lớn khi ánh sáng cá nhân của họ đi vào đúng vai trò, đúng trách nhiệm và đúng quỹ đạo chung.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1bfebf42-2ca9-4675-a71e-a93a01eac108','46063ee0-4653-4eb1-b110-dad96c9545c5',3,'text','Mô hình S.T.A.R.S gợi ra đúng hình ảnh ấy: mỗi nhân sự là một ngôi sao, và họ chỉ tỏa sáng bền vững khi hội tụ đủ năm cánh là Skills, Traits, Actions, Results và Synergy, trong khi phần lõi ở trung tâm phải là ONE LIGHT.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d0130fdf-6a3b-4686-8af5-df0e4f0289bb','46063ee0-4653-4eb1-b110-dad96c9545c5',4,'text','Có những nơi xem con người như một mắt xích có thể thay thế bất cứ lúc nào. Nhưng cũng có những tổ chức hiểu rằng, nếu muốn đi xa, họ không thể chỉ gom những bàn tay để làm việc; họ phải biết đánh thức những vì sao đang ngủ yên trong mỗi con người. Và khi một người thật sự trưởng thành trong tổ chức, họ không chỉ biết làm việc, mà còn biết giữ vai trò, giữ lời, giữ tiêu chuẩn, giữ nhịp phối hợp và giữ ánh sáng của mình không làm chói lóa người khác.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f834b6fa-6d76-47a8-b1df-9a1db8bb603e','46063ee0-4653-4eb1-b110-dad96c9545c5',5,'text','Một ngôi sao không thể thành hình nếu thiếu cánh, và một con người trong tổ chức cũng không thể trưởng thành toàn diện nếu chỉ mạnh ở một mặt mà khuyết ở những mặt còn lại.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b5dc5b75-4115-4d70-bfd6-5a8e36ed930f','46063ee0-4653-4eb1-b110-dad96c9545c5',6,'text','- Skills là năng lực làm đúng việc; - Traits là phẩm chất khiến người khác tin cậy; - Actions là sức làm đều mỗi ngày; - Results là những gì được đo bằng kết quả rõ ràng; - Synergy là khả năng hòa mình vào đội ngũ để tạo ra giá trị lớn hơn nỗ lực của từng cá nhân cộng lại.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('10b19dfd-e8f1-4ead-9727-239fe9b25eb7','46063ee0-4653-4eb1-b110-dad96c9545c5',7,'text','Vì thế, người giỏi chuyên môn mà thiếu phẩm chất sẽ khó tạo niềm tin; người chăm chỉ mà không tạo kết quả thì chỉ mới bận rộn; còn người có thành tích nhưng không biết phối hợp lại dễ trở thành một điểm sáng đơn độc giữa bầu trời tối. S.T.A.R.S không ca ngợi kiểu “ngôi sao cô độc”, mà hướng đến một kiểu ngôi sao biết tỏa sáng trong cấu trúc, nơi mỗi người hiểu mình là ai, giữ vai trò gì, cần làm gì mỗi ngày, được đo bằng gì và đang đóng góp gì cho khách hàng cũng như tổ chức.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2c05e18e-068f-4805-ab47-d471aa4bf50e','46063ee0-4653-4eb1-b110-dad96c9545c5',8,'text','Mô hình quản trị S.T.A.R.S là một khung quản trị con người được thiết kế cho tổ chức nhằm đánh giá nhân sự, chuẩn hóa năng lực, hành vi, kết quả, phối hợp nội bộ và cơ chế đãi ngộ theo một hệ quy chiếu thống nhất.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ece36be8-8676-4548-9e7b-47fad9ae19ff','06-stars-luong-thuong','33a50907-47c8-47f7-af7c-601ff1920332',2,'Mục tiêu quản trị','muc-tieu-quan-tri',2,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('def5e472-f294-4ffa-9057-200b338b3c06','ece36be8-8676-4548-9e7b-47fad9ae19ff',9,'text','Trong một phòng khám nha khoa, con người không chỉ là lực lượng vận hành. Họ là nơi chất lượng chuyên môn, niềm tin của khách hàng và đạo đức nghề nghiệp đi qua mỗi ngày để trở thành trải nghiệm thật. Vì vậy, S.T.A.R.S không được xây như một bộ tiêu chí nhân sự thông thường, mà như một lớp vận hành con người đặt bên trong hệ quản trị lớn hơn của tổ chức, nơi mọi tiêu chuẩn đều phải phục vụ cho lợi ích của người bệnh và sự bền vững của phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('50ec1d93-05d6-40d2-a7f9-aa5e23377dd9','ece36be8-8676-4548-9e7b-47fad9ae19ff',10,'text','Triết lý nền của mô hình là một phòng khám không thể tăng trưởng bền vững nếu chỉ dựa vào doanh thu, quảng bá hay kỹ thuật. Nó phải được xây trên nền của chất lượng chuyên môn, phẩm chất nghề nghiệp, kỷ luật thực thi, minh bạch kết quả và khả năng hiệp lực của đội ngũ. Chính từ nền đó, S.T.A.R.S trở thành bộ khung giúp chuẩn hóa con người, liên kết năng lực với hiệu suất, tạo cơ sở minh bạch cho đánh giá và bảo đảm tăng trưởng không tách khỏi y đức.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('edeaa97e-7034-4569-8b7e-4c006b656ed5','ece36be8-8676-4548-9e7b-47fad9ae19ff',11,'text','Có những tổ chức lớn lên bằng tiền, bằng quảng cáo, bằng tốc độ. Nhưng cũng có những tổ chức lớn lên bằng phẩm chất của con người mà họ dám tin tưởng, dám đào tạo và dám giữ chuẩn đến cùng. Trong lĩnh vực nha khoa, nơi một quyết định chuyên môn có thể chạm trực tiếp đến sức khỏe, trải nghiệm và niềm tin của người bệnh, tổ chức càng không thể để con người vận hành theo cảm tính.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bfee6310-b630-48b3-b4b5-25b05676123e','ece36be8-8676-4548-9e7b-47fad9ae19ff',12,'text','S.T.A.R.S ra đời để trả lời đúng câu hỏi ấy: làm thế nào để mỗi nhân sự vừa là một cá thể có năng lực riêng, vừa là một mắt xích đáng tin trong hệ thống chung. Mô hình này không nhìn con người như “người làm công”, mà như một ngôi sao phải có năm cánh: Skills, Traits, Actions, Results và Synergy; và ở giữa là ONE LIGHT - một lòng sống với tử tế và đạo đức.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('45ffe029-de9b-49bb-9709-407f499a67d2','06-stars-luong-thuong','33a50907-47c8-47f7-af7c-601ff1920332',2,'Ý nghĩa quản trị','y-nghia-quan-tri',3,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3b2caa07-747a-4f56-9802-d60b26a0651f','45ffe029-de9b-49bb-9709-407f499a67d2',13,'text','Ý nghĩa sâu nhất của S.T.A.R.S nằm ở chỗ nó biến con người từ đối tượng được đánh giá bằng cảm nhận thành đối tượng được **quản trị bằng tiêu chuẩn**. Khi một tổ chức có cùng ngôn ngữ về năng lực, hành vi, kết quả và phối hợp, họ sẽ không còn phải tranh cãi mãi về cảm giác đúng hay sai. Họ có thể quay về với dữ liệu, vai trò, checklist và KPI để nhìn nhận nhân sự một cách công bằng hơn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('58db3a76-dc8d-4167-99bb-5c307ad2ad07','45ffe029-de9b-49bb-9709-407f499a67d2',14,'text','Cách nhìn này giúp phòng khám thoát khỏi kiểu quản trị bằng ấn tượng hoặc cảm xúc. Một người không được đánh giá chỉ vì họ “có vẻ chăm chỉ” hay “nói chuyện dễ nghe”, mà phải được nhìn qua năng lực, hành động, kết quả và khả năng phối hợp trong một cấu trúc có thể đo lường. Nhờ vậy, đánh giá, đào tạo, lương thưởng và thăng tiến đều có nền tảng rõ ràng hơn, công bằng hơn và ít phụ thuộc vào cảm tính hơn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('913eeab8-11c2-41cc-be84-4582cd92ab36','06-stars-luong-thuong','33a50907-47c8-47f7-af7c-601ff1920332',2,'Bốn mục tiêu','bon-muc-tieu',4,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('306e4a5d-668c-4a7a-8fa7-0cca7f544f60','913eeab8-11c2-41cc-be84-4582cd92ab36',15,'text','Từ góc nhìn quản trị, S.T.A.R.S phục vụ bốn mục tiêu đồng thời.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('500c64f8-0818-4a28-b78e-93a225d44a57','913eeab8-11c2-41cc-be84-4582cd92ab36',16,'text','- Thứ nhất, nó chuẩn hóa tiêu chuẩn con người theo cùng một ngôn ngữ quản trị, để mọi vai trò đều hiểu cùng một hệ tiêu chuẩn. - Thứ hai, nó liên kết năng lực cá nhân với hiệu suất tập thể và kết quả vận hành, để một người giỏi không đứng riêng một chỗ mà trở thành đóng góp thật cho hệ thống.- Thứ ba, nó tạo ra nền tảng minh bạch cho đào tạo, lương thưởng và thăng tiến, giúp đội ngũ biết rõ vì sao mình được ghi nhận và vì sao mình cần cải thiện. - Thứ tư, nó bảo đảm rằng tăng trưởng của phòng khám không tách rời khỏi chất lượng điều trị và đạo đức nghề nghiệp, để phòng khám đi xa mà không đi lệch.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('9bffdbd7-25d5-4d5e-884a-197085110f4e','06-stars-luong-thuong','33a50907-47c8-47f7-af7c-601ff1920332',2,'Kết nối với ROOTS','ket-noi-voi-roots',5,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e627c67a-b375-4792-b20a-4b8d71e13b7b','9bffdbd7-25d5-4d5e-884a-197085110f4e',17,'text','Triết lý trung tâm của mô hình được đặt trên ROOTS như một nền móng giá trị. Điều đó có nghĩa là tăng trưởng trong y tế không thể được đo bằng doanh thu đơn thuần, mà phải được soi bằng chất lượng chuyên môn, phẩm chất nghề, kỷ luật thực thi, minh bạch kết quả và hiệp lực đội ngũ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3b86c9ed-9f6f-4023-bb9a-70ef6944a4d4','9bffdbd7-25d5-4d5e-884a-197085110f4e',18,'text','Vì thế, S.T.A.R.S không đứng một mình. Nó vận hành như lớp con người bên trong một hệ thống lớn hơn, nơi Dental Empire OS quản trị toàn cục, S.T.A.R.S People OS chuẩn hóa con người, và Empire Circle (S3 Holacracy Lite) giúp vai trò, vòng tròn, quyền hạn và cải tiến được vận hành có trật tự. Khi ba lớp này khớp nhau, phòng khám mới có thể phát triển bền vững mà vẫn giữ được chất lượng và y đức.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b29fd1eb-2b68-44fe-aca9-42d73356d5b9','06-stars-luong-thuong','33a50907-47c8-47f7-af7c-601ff1920332',2,'Kết bài','ket-bai',6,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('edb2f8f9-adb3-428a-a8e9-456f5c9e135e','b29fd1eb-2b68-44fe-aca9-42d73356d5b9',19,'text','S.T.A.R.S, xét đến cùng, không chỉ là một mô hình nhân sự. Nó là một lời nhắc rằng tổ chức bền vững phải bắt đầu từ con người được đặt đúng chuẩn, đúng vai và đúng giá trị. Một đội ngũ như vậy không chỉ biết làm việc, mà biết giữ nghề, giữ niềm tin và giữ cho hệ thống không đánh đổi chất lượng lấy tăng trưởng ngắn hạn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('766c805c-bb84-4106-921d-c158558a9246','b29fd1eb-2b68-44fe-aca9-42d73356d5b9',20,'text','Khi năm cánh **Skills, Traits, Actions, Results và Synergy** cùng hội tụ trong ánh sáng của **ONE LIGHT**, phòng khám không còn vận hành như một tập hợp cá nhân rời rạc. Nó trở thành một chòm sao có trật tự, nơi mỗi người sáng lên bằng năng lực của mình nhưng vẫn cùng hướng về một mục tiêu chung: tạo ra giá trị điều trị an toàn, chuyên nghiệp và bền vững cho người bệnh.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('d5f04b0c-a055-4df8-8545-54334e151ac2','06-stars-luong-thuong',NULL,1,'6.2 CẤU TRÚC CỦA S.T.A.R.S','62-cau-truc-cua-stars',7,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9b46a64e-8abb-4914-a349-e9b856e5a187','d5f04b0c-a055-4df8-8545-54334e151ac2',21,'text','S.T.A.R.S được xây trên năm trụ cột để mỗi thành viên không chỉ làm việc tốt, mà còn trưởng thành đúng chuẩn trong hệ thống. Năm trụ cột ấy là Skills, Traits, Actions, Results và Synergy; còn ONE LIGHT là lõi giữ cho cả năm trụ cột không lệch khỏi đạo đức nghề nghiệp và lợi ích của người bệnh.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6c0e02c2-8a5a-47c9-89db-d73fcbc7f28f','d5f04b0c-a055-4df8-8545-54334e151ac2',22,'image',NULL,'book/06-stars-luong-thuong/9e02960d-0531-4d52-9b12-63bc1a1cf2de-img01.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('a2e6a1c4-f65b-4242-bb4d-aad12a3250b6','06-stars-luong-thuong','d5f04b0c-a055-4df8-8545-54334e151ac2',2,'S - SKILL (Kỹ năng)','s-skill-ky-nang',8,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c1d74ee7-acc5-47a0-969f-fc6f4273a2ae','a2e6a1c4-f65b-4242-bb4d-aad12a3250b6',23,'text','- Skills là cánh sao đầu tiên và là nơi bắt đầu của giá trị. - Skills là năng lực làm đúng việc. Đây là phần gốc của chất lượng chuyên môn, nơi một nhân sự chứng minh rằng họ không chỉ có mặt trong tổ chức, mà còn có khả năng tạo ra giá trị thật bằng tay nghề, kiến thức và sự chính xác trong thực hành.- Trong phòng khám nha khoa, Skills trước hết thuộc về năng lực lâm sàng, khả năng chẩn đoán, thao tác, xử lý tình huống và tuân thủ quy trình chuyên môn. Nếu Skills yếu, mọi thứ phía sau đều khó bền; vì một tổ chức không thể xây niềm tin dài hạn trên một nền năng lực mỏng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1e49c486-815a-4db6-9258-d2351304b47b','06-stars-luong-thuong','d5f04b0c-a055-4df8-8545-54334e151ac2',2,'T - TRAITS (Tố chất)','t-traits-to-chat',9,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('91ad32d3-2653-4a80-8ec7-83fd263e8116','1e49c486-815a-4db6-9258-d2351304b47b',24,'text','- Traits là cánh sao thứ hai và là phần tạo nên độ tin cậy của một con người. - Traits là tố chất khiến người khác tin cậy. Đây không chỉ là tính cách theo nghĩa thông thường, mà là độ vững của một con người trong kỷ luật, trách nhiệm, sự ổn định, cẩn trọng và thái độ làm việc.- Trong tổ chức, Traits cho biết một người có thể được giao việc hay không, có giữ lời hay không, có làm việc đều hay không, và có đủ nền phẩm chất để đi đường dài cùng đội ngũ hay không. Người có Skills mà thiếu Traits thì dễ giỏi nhưng khó bền; còn người có Traits tốt thường tạo ra cảm giác yên tâm, từ đó giúp hệ thống vận hành mượt hơn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('39b6716e-5db8-4567-829a-68f2f3cb0d27','06-stars-luong-thuong','d5f04b0c-a055-4df8-8545-54334e151ac2',2,'A -ACTIONS (Hành động)','a-actions-hanh-ong',10,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9d1af41f-52a2-45d1-8dd9-6ed5550cfd6a','39b6716e-5db8-4567-829a-68f2f3cb0d27',25,'text','- Actions là cánh sao thứ ba và là ánh sáng của ngôi sao.- Actions là sức làm đều mỗi ngày. Đây là cánh tay của S.T.A.R.S, biến năng lực và phẩm chất thành nhịp thực thi cụ thể qua checklist, follow-up, giao tiếp, bàn giao, chăm sóc và cải tiến.- Một tổ chức không thể chỉ sống bằng ý định tốt. Muốn tạo ra kết quả thật, con người phải biết làm đúng việc vào đúng thời điểm, lặp lại đúng chuẩn mỗi ngày, không bỏ sót, không làm cho có và không chờ cảm hứng mới hành động.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('77850633-389a-460b-9fd2-5b9a56657624','06-stars-luong-thuong','d5f04b0c-a055-4df8-8545-54334e151ac2',2,'R - RESULTS (Kết quả)','r-results-ket-qua',11,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('79fbe14a-56b2-4662-99b1-afbb1fd55c0a','77850633-389a-460b-9fd2-5b9a56657624',26,'text','- Results là cánh sao thứ tư, nơi mọi nỗ lực phải đi qua cánh cửa của thực tế. - Results là kết quả rõ ràng có thể đo lường. Đây là phần S.T.A.R.S dùng để chứng minh rằng nỗ lực không chỉ dừng ở mức bận rộn, mà thật sự đi tới giá trị tạo ra cho khách hàng và cho phòng khám.- Trong thực hành nha khoa, Results không chỉ là doanh thu. Nó còn là tỷ lệ điều trị hoàn tất, tỷ lệ tái khám, mức hài lòng, số review, số referral, hiệu suất từng vai trò và hiệu quả từng Circle. Kết quả là nơi mọi nỗ lực phải đi qua thực tế, vì một tổ chức trưởng thành không thể đánh giá con người bằng cảm giác thay vì bằng dữ liệu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('8fcfecaf-92aa-490d-ae5a-8fd1e9f0b781','06-stars-luong-thuong','d5f04b0c-a055-4df8-8545-54334e151ac2',2,'S - SYNERGY (Hiệp lực)','s-synergy-hiep-luc',12,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cb2fbd72-c722-46c1-8509-1c0be18346cc','8fcfecaf-92aa-490d-ae5a-8fd1e9f0b781',27,'text','- Synergy là khả năng hòa mình vào đội ngũ để tạo ra giá trị lớn hơn tổng nỗ lực của từng cá nhân. Đây là trụ cột giúp tổ chức thoát khỏi kiểu mạnh ai nấy làm, chuyển sang cách vận hành có phối hợp, có bàn giao, có nhịp và có mục tiêu chung.- Synergy đặc biệt quan trọng trong phòng khám, vì trải nghiệm của người bệnh không bao giờ được tạo ra bởi một người duy nhất. Nó được tạo nên từ sự ăn khớp giữa lễ tân, CSKH, bác sĩ, phụ tá, marketing, tài chính và lãnh đạo; thiếu một mắt xích, toàn bộ hành trình có thể bị gãy.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1c2c9e76-e814-46f4-bb9a-ab5770574ee4','06-stars-luong-thuong','d5f04b0c-a055-4df8-8545-54334e151ac2',2,'ONE LIGHT','one-light',13,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a791e79c-017f-47ee-bb8f-074b1edbb9ae','1c2c9e76-e814-46f4-bb9a-ab5770574ee4',28,'text','Năm trụ cột chỉ thật sự có ý nghĩa khi được giữ bởi ONE LIGHT ở trung tâm. ONE LIGHT là tử tế, chính trực, minh bạch, giữ lời và làm đúng; nó ngăn Skills trở thành kỹ thuật vô cảm, ngăn Actions trở thành chăm chỉ mù quáng, ngăn Results biến thành thành tích bằng mọi giá, và ngăn Synergy trôi thành sự đồng thuận hình thức.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e2d2b351-6aa4-4b34-9963-4494a8dfa9bb','1c2c9e76-e814-46f4-bb9a-ab5770574ee4',29,'text','Đây cũng là điểm làm cho S.T.A.R.S khác với một bộ khung đánh giá nhân sự đơn thuần. Mục tiêu của mô hình không phải chỉ là chọn người giỏi hơn, mà là nuôi dưỡng một đội ngũ giỏi, tin cậy, đều đặn, có kết quả và biết phối hợp trong khuôn khổ đạo đức nghề nghiệp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d8697c93-f0b7-42a7-bc49-70ca81a7fd18','1c2c9e76-e814-46f4-bb9a-ab5770574ee4',30,'text','S.T.A.R.S, vì thế, không chỉ là một mô hình nhân sự. Nó là một cách nhìn con người bằng niềm tin có cấu trúc. Nó nói rằng mỗi nhân sự đều có thể trở thành một ngôi sao, nhưng sự tỏa sáng ấy không đến từ danh xưng, mà đến từ quá trình trưởng thành: học đúng năng lực, rèn đúng phẩm chất, làm đều công việc, tạo ra kết quả, biết phối hợp và giữ được tâm sáng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('46ae828b-3d02-45f1-aa78-5d790f65b53a','1c2c9e76-e814-46f4-bb9a-ab5770574ee4',31,'text','Khi tổ chức được xây trên những ngôi sao như vậy, tổ chức ấy không còn vận hành bằng sự thúc ép. Nó vận hành bằng sự rõ ràng. Mỗi người biết mình là ai, giữ vai trò gì, cần làm gì, được đo bằng gì, phối hợp với ai và đóng góp ra sao cho hành trình lớn hơn của cả hệ thống. Lúc đó, tổ chức không còn là một nơi tập hợp người làm thuê. Nó trở thành một **bầu trời có trật tự, nơi mỗi ngôi sao phát sáng đúng quỹ đạo của mình**, và chính từ sự đúng đắn ấy, sức mạnh chung được sinh ra.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f16a9c08-113c-47c6-a0c5-efaddc402538','1c2c9e76-e814-46f4-bb9a-ab5770574ee4',32,'image',NULL,'book/06-stars-luong-thuong/c1319255-5d80-4cc9-bd15-b65c04d7f1f4-img02.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('45326817-8c56-40a8-a695-433fad6ce16d','06-stars-luong-thuong',NULL,1,'6.3 CƠ CHẾ ĐÃI  NGỘ THEO S.T.A.R.S','63-co-che-ai-ngo-theo-stars',14,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('847f6595-ff44-4e85-bc16-4422c994a09c','45326817-8c56-40a8-a695-433fad6ce16d',33,'text','Một ưu điểm quan trọng của mô hình S.T.A.R.S là có thể chuyển hóa trực tiếp thành cơ chế lương thưởng. Mục tiêu của thiết kế này là tạo ra sự công bằng tương đối: người lao động được trả cho nền trách nhiệm, được ghi nhận vì năng lực ổn định, được thưởng vì kết quả thực tế và được khuyến khích vì đóng góp cho tập thể.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('de6b9d11-3370-411e-a182-68420126ee25','45326817-8c56-40a8-a695-433fad6ce16d',34,'text','Trong một phòng khám, lương thưởng không nên chỉ là con số để trả công, mà phải là một **công cụ điều chỉnh hành vi và củng cố văn hóa**. Nếu thu nhập tách khỏi vai trò, tách khỏi năng lực, tách khỏi kết quả và tách khỏi hiệp lực, hệ thống sẽ dễ rơi vào cảm tính, chênh lệch và mất động lực dài hạn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1a2516f5-efc1-4ff9-a98b-eb71ed31c761','06-stars-luong-thuong','45326817-8c56-40a8-a695-433fad6ce16d',2,'1. Cấu trúc thu nhập chung','1-cau-truc-thu-nhap-chung',15,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7b342cd1-c039-4bb0-bec6-e63a5b7fdbfd','1a2516f5-efc1-4ff9-a98b-eb71ed31c761',35,'image',NULL,'book/06-stars-luong-thuong/d56f1cf7-4397-414d-844c-aad8495ea513-img03.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b4397044-aaf8-43ef-9b1c-bea9ff00557d','1a2516f5-efc1-4ff9-a98b-eb71ed31c761',36,'text','Công thức tổng hợp thu nhập trong mô hình S.T.A.R.S được thiết kế để phản ánh đầy đủ giá trị thật mà một nhân sự tạo ra cho phòng khám. Thay vì chỉ trả theo thời gian làm việc hay chỉ thưởng theo doanh thu, mô hình này ghép bốn lớp thu nhập thành một cấu trúc thống nhất, trong đó mỗi lớp đại diện cho một dạng đóng góp khác nhau.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6e00c0b5-1bc8-461a-b085-1b6fe855b4a8','1a2516f5-efc1-4ff9-a98b-eb71ed31c761',37,'text','Trong đó, lương cứng là phần nền của vai trò; phụ cấp S.T ghi nhận năng lực ổn định; thưởng A.R trả cho hành động và kết quả thực tế; còn thưởng Hiệp lực dành cho đóng góp vào sức mạnh chung của tập thể. Cách thiết kế này giúp thu nhập không bị lệch về một phía, mà phản ánh đồng thời trách nhiệm, năng lực, hiệu suất và tinh thần phối hợp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0c9518a5-a71b-40b1-99f2-62c502d7fdd3','1a2516f5-efc1-4ff9-a98b-eb71ed31c761',38,'text','Điểm quan trọng của công thức này là mỗi thành phần phải được đo bằng tiêu chí riêng và không được thay thế cho nhau. Một người có thể có lương cứng cao vì giữ vai trò lớn, nhưng nếu năng lực nền yếu thì phụ cấp S.T phải thấp; ngược lại, một người làm đều và có kết quả tốt sẽ được ghi nhận rõ hơn ở phần thưởng A.R và Synergy.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('386ace62-15cf-4566-9e3a-9cc77ada4d9f','1a2516f5-efc1-4ff9-a98b-eb71ed31c761',39,'text','Công thức này cũng giữ cho thu nhập đi cùng văn hóa tử tế. Nghĩa là mô hình không khuyến khích việc “làm số” bằng mọi giá, không thưởng cho kết quả tạo ra từ sai lệch Integrity, và không để thành tích ngắn hạn lấn át chất lượng dài hạn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('10bec431-2477-4482-abc6-8218a89d2287','1a2516f5-efc1-4ff9-a98b-eb71ed31c761',40,'text','Nói ngắn gọn, tổng thu nhập theo S.T.A.R.S là một cấu trúc có nền, có chất lượng, có hiệu suất và có hiệp lực; nhờ đó, phần được trả cho mỗi người phản ánh đúng giá trị họ mang lại cho hệ thống.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d29320b3-bffe-4d18-8c7c-dad50671544d','1a2516f5-efc1-4ff9-a98b-eb71ed31c761',41,'text','Thu nhập theo S.T.A.R.S được thiết kế theo bốn lớp:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b7ff5e3f-43f0-42df-8cbe-77e9bacc8107','1a2516f5-efc1-4ff9-a98b-eb71ed31c761',42,'text','**Lương cứng + Phụ cấp S.T + Thưởng A.R + Thưởng Hiệp lực**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d3979a2e-c2d1-45ef-a06c-6ffa0f95dd7d','1a2516f5-efc1-4ff9-a98b-eb71ed31c761',43,'text','Mỗi lớp trả cho một phần giá trị khác nhau của con người trong hệ thống, từ nền trách nhiệm đến đóng góp vượt trội cho tổ chức.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('09b7da3d-31f1-44ba-91c5-a43a84a428da','1a2516f5-efc1-4ff9-a98b-eb71ed31c761',44,'text','- Lương cứng trả cho vai trò, thời gian hiện diện và trách nhiệm nền.- Phụ cấp S.T trả cho kỹ năng và tố chất ổn định.- Thưởng A.R trả cho hành động đúng và kết quả đo được.- Thưởng Hiệp lực trả cho sự phối hợp tạo ra giá trị chung.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('564fd16b-d3b8-4011-b97c-2ca991b5ab5c','06-stars-luong-thuong','45326817-8c56-40a8-a695-433fad6ce16d',2,'2. Ý nghĩa từng thành phần','2-y-nghia-tung-thanh-phan',16,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('a383ca20-fb5a-46f2-92c0-9626e5028fb5','06-stars-luong-thuong','564fd16b-d3b8-4011-b97c-2ca991b5ab5c',3,'Lương cứng','luong-cung',17,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7d619650-0861-4a3e-b5f0-1ae0cf31334c','a383ca20-fb5a-46f2-92c0-9626e5028fb5',45,'text','Lương cứng là phần thu nhập nền của mỗi nhân sự, được trả cho vai trò, thời gian hiện diện và trách nhiệm cơ bản trong tổ chức. Đây là phần giúp người lao động có sự ổn định tối thiểu để yên tâm làm việc, đồng thời phản ánh rằng mỗi vị trí đều có giá trị nền cần được công nhận.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('58119e7a-7ec5-4d8c-8885-fbb02cf023f1','a383ca20-fb5a-46f2-92c0-9626e5028fb5',46,'text','Trong mô hình S.T.A.R.S, lương cứng không phải là phần thưởng cho thành tích, mà là sự ghi nhận cho việc một người đang giữ một vai trò cụ thể trong hệ thống. Nghĩa là dù kết quả tháng đó tốt hay chưa tốt, phần lương cứng vẫn đại diện cho trách nhiệm mà họ đang gánh, cho sự hiện diện đều đặn của họ và cho việc họ đã góp mặt trong cấu trúc vận hành của phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b8e33075-6b24-407e-9e60-a0530065291c','a383ca20-fb5a-46f2-92c0-9626e5028fb5',47,'text','Thiết kế lương cứng cần dựa trên mức độ phức tạp của vai trò, yêu cầu chuyên môn, tính liên tục của công việc và mức trách nhiệm đi kèm. Vai trò càng quan trọng, càng đòi hỏi sự ổn định cao, càng liên quan trực tiếp đến trải nghiệm người bệnh hoặc hiệu quả hệ thống, thì lương cứng càng phải được xác lập rõ và đủ chắc để giữ người phù hợp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b2724e75-7988-45b1-8db6-70ce2f498e17','a383ca20-fb5a-46f2-92c0-9626e5028fb5',48,'text','Lương cứng cũng là nền để phòng khám tránh hai sai lầm thường gặp. Một là chỉ trả theo cảm tính, khiến nhân sự không biết giá trị vai trò của mình nằm ở đâu. Hai là dồn toàn bộ thu nhập vào thưởng, khiến người lao động luôn ở trạng thái bất định và khó xây dựng cam kết dài hạn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('94a0ed96-1c84-4927-9c1e-ef21aebc997f','a383ca20-fb5a-46f2-92c0-9626e5028fb5',49,'text','Nói ngắn gọn, lương cứng là phần trả cho vai trò và trách nhiệm nền; nó tạo sự ổn định để con người làm việc tử tế, đều đặn và có cam kết trong hệ thống.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('29a41b63-4692-4a83-8c7e-cc7ec3ccb7db','06-stars-luong-thuong','564fd16b-d3b8-4011-b97c-2ca991b5ab5c',3,'Phụ cấp S.T','phu-cap-st',18,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7a5ebca3-264e-4f5c-ade5-2934729e1659','29a41b63-4692-4a83-8c7e-cc7ec3ccb7db',50,'text','Phụ cấp S.T là phần thu nhập bổ sung dành cho **Skills **và **Traits**, tức năng lực chuyên môn và tố chất nghề nghiệp ổn định. Nếu lương cứng trả cho vị trí, thì phụ cấp S.T trả cho chất lượng của con người đang đứng trong vị trí ấy.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('df3155ad-3791-4b29-8e30-d1e14eaa34db','29a41b63-4692-4a83-8c7e-cc7ec3ccb7db',51,'text','Skills ở đây là năng lực làm đúng việc, đúng chuẩn, đúng quy trình; còn Traits là nền phẩm chất giúp người đó đáng tin cậy trong thực hành hằng ngày. Một người có tay nghề tốt, làm việc chính xác, giữ kỷ luật, cẩn trọng, chủ động và ổn định sẽ tạo ra giá trị khác với người chỉ làm được việc ở mức tối thiểu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('24251c7a-5524-4620-bf63-1f50ba337188','29a41b63-4692-4a83-8c7e-cc7ec3ccb7db',52,'text','Phụ cấp S.T không nên hiểu như khoản thưởng cảm tính cho người “có vẻ giỏi”, mà phải là phần ghi nhận có cơ sở cho năng lực nền đã được quan sát và kiểm chứng. Cơ sở đó có thể đến từ chuyên môn, mức độ tuân thủ quy trình, khả năng tự quản, độ ổn định trong giao tiếp, độ ít sai sót và khả năng học hỏi sau đào tạo.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0413972e-c44b-4051-be14-bcb2590fa074','29a41b63-4692-4a83-8c7e-cc7ec3ccb7db',53,'text','Trong phòng khám nha khoa, phụ cấp S.T đặc biệt quan trọng vì đây là ngành mà năng lực chuyên môn và độ tin cậy nghề nghiệp gắn chặt với chất lượng điều trị. Người có năng lực ổn định không chỉ làm tốt công việc của mình, mà còn làm cho cả hệ thống yên tâm hơn khi giao việc, bàn giao việc và phối hợp liên phòng ban.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f3f89374-c1ca-43f6-af7f-0b0ff81056dd','29a41b63-4692-4a83-8c7e-cc7ec3ccb7db',54,'text','Nói đơn giản, phụ cấp S.T là phần thu nhập trả cho tay nghề, tác phong và độ tin cậy; nó khuyến khích con người nâng chất lượng nền thay vì chỉ chạy theo kết quả ngắn hạn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('39495043-5b5f-40ec-b3f3-cfad0d0465ad','06-stars-luong-thuong','564fd16b-d3b8-4011-b97c-2ca991b5ab5c',3,'Thưởng A.R','thuong-ar',19,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('586f3061-63ae-4934-8ff5-95d7cf87f002','39495043-5b5f-40ec-b3f3-cfad0d0465ad',55,'text','Thưởng A.R là phần thưởng dành cho **Actions **và **Results**, tức hành động thực tế và kết quả đo lường được. Đây là phần thu nhập phản ánh trực tiếp mức độ thực thi công việc hằng ngày và giá trị đầu ra mà một nhân sự tạo ra cho phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('13dab681-8d6e-4a7f-a52e-66ff39c837a5','39495043-5b5f-40ec-b3f3-cfad0d0465ad',56,'text','Actions là việc làm đều, làm thật và làm đúng mỗi ngày qua checklist, theo sát khách hàng, phản hồi kịp thời, hoàn tất đầu việc và cải tiến liên tục. Results là phần đầu ra có thể đo bằng số liệu như doanh thu, chuyển đổi, tỷ lệ chốt, tỷ lệ tái khám, mức hoàn thành KPI hay hiệu suất của từng vai trò.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('54c80f8b-5d21-48ae-a88d-359a49f13ada','39495043-5b5f-40ec-b3f3-cfad0d0465ad',57,'text','Điểm quan trọng nhất của Thưởng A.R là nó phải gắn với hành vi đúng và kết quả thật, chứ không gắn với số liệu được tạo ra bằng cách làm sai ONE LIGHT. Vì vậy, phòng khám chỉ nên thưởng khi hành động hợp chuẩn và kết quả tạo ra có giá trị thực cho khách hàng, đội ngũ và hệ thống.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c8fd5e07-d781-4326-884d-6df1548d0632','39495043-5b5f-40ec-b3f3-cfad0d0465ad',58,'text','Ví dụ:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f5476aa7-6516-4a2f-b0b6-f2128831e998','39495043-5b5f-40ec-b3f3-cfad0d0465ad',59,'text','- Không thưởng booking nếu tư vấn sai sự thật.- Không thưởng review nếu ép khách hoặc xin review sai thời điểm.- Không thưởng doanh thu nếu bác sĩ làm dư hoặc tư vấn quá mức.- Không thưởng lead nếu lead không chất lượng hoặc không chuyển đổi.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('504fa097-cc3e-4bce-8c08-9992dcefd62f','39495043-5b5f-40ec-b3f3-cfad0d0465ad',60,'text','Cách thiết kế này giúp đội ngũ hiểu rằng năng suất không phải là sự bận rộn, mà là năng lực tạo ra kết quả đúng bằng cách đúng. Khi Thưởng A.R được vận hành chuẩn, tổ chức sẽ khuyến khích được thói quen làm đều, làm chuẩn và làm ra giá trị thật.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c644603b-30f4-4251-8d2c-e564cedd42a5','39495043-5b5f-40ec-b3f3-cfad0d0465ad',61,'text','Nói ngắn gọn, Thưởng A.R là phần thu nhập trả cho hành động đúng và kết quả rõ; nó giúp đội ngũ tập trung vào thực thi và hiệu quả thay vì chỉ vào hình thức bề ngoài.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('43ac912f-f861-4c25-a691-740a03914b96','06-stars-luong-thuong','564fd16b-d3b8-4011-b97c-2ca991b5ab5c',3,'Thưởng Synergy','thuong-synergy',20,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b70e88a7-9a27-40ae-9a6c-08d3c8db22f7','43ac912f-f861-4c25-a691-740a03914b96',62,'text','Thưởng Synergy là phần thưởng dành cho kết quả chung của toàn phòng khám hoặc của từng Circle, nhằm khuyến khích tinh thần phối hợp thay vì tối ưu lợi ích cá nhân. Nếu Thưởng A.R trả cho đóng góp cá nhân, thì Thưởng Synergy trả cho sức mạnh tập thể.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6ef21b37-d32d-4092-a32a-d59d70d48b4f','43ac912f-f861-4c25-a691-740a03914b96',63,'text','Trong một phòng khám nha khoa, giá trị cuối cùng của trải nghiệm khách hàng hiếm khi đến từ một người riêng lẻ. Nó được tạo ra bởi sự ăn khớp giữa marketing, lễ tân, tư vấn, bác sĩ, phụ tá, CSKH, tài chính và vận hành. Vì vậy, nếu chỉ thưởng theo thành tích cá nhân mà bỏ qua sự phối hợp, hệ thống sẽ dễ mạnh cục bộ nhưng yếu tổng thể.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d1049021-91cf-4e8a-8227-1553acf111a4','43ac912f-f861-4c25-a691-740a03914b96',64,'text','Thưởng Synergy vì thế cần gắn với những chỉ số chung như trải nghiệm khách hàng, chất lượng bàn giao, tỷ lệ phối hợp nội bộ, review, referral, mức hoàn thành mục tiêu của Circle và mức độ ổn định của quy trình. Đây là phần thưởng giúp đội ngũ hiểu rằng một người giỏi chưa chắc đã đủ, nhưng một đội ngũ ăn khớp sẽ tạo ra giá trị lớn hơn rất nhiều.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('94e77ded-7d18-4bbc-afe4-806542e50da9','43ac912f-f861-4c25-a691-740a03914b96',65,'text','Tuy nhiên, Thưởng Synergy phải có nguyên tắc rõ. Nó không được thay thế thưởng cá nhân, không được chia đều theo cảm tính, và càng không được dùng để hợp thức hóa hành vi sai chuẩn của một bộ phận nào đó. Nếu có người vi phạm nghiêm trọng Integrity, phần thưởng chung không thể trở thành tấm màn che cho lỗi đó.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f4e7e108-3bcd-42b6-b5fb-fd86bcc02e36','43ac912f-f861-4c25-a691-740a03914b96',66,'text','Ví dụ:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cb386cfb-f83c-410a-bfad-01573f7e23f7','43ac912f-f861-4c25-a691-740a03914b96',67,'text','- Không nên chỉ thưởng cho sales nếu doanh thu tăng, vì doanh thu còn đến từ marketing, lễ tân, bác sĩ, phụ tá và CSKH.- Không nên chỉ thưởng cho người xin review, vì review tốt đến từ cả trải nghiệm điều trị và chăm sóc.- Không nên thưởng đội nhóm nếu có hành vi làm sai ONE LIGHT để đạt số.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ecdd3b0a-3494-4b1e-8fe1-d4673fd2a2b5','43ac912f-f861-4c25-a691-740a03914b96',68,'text','Nói ngắn gọn, Thưởng Synergy là phần thu nhập trả cho sự phối hợp và kết quả chung; nó giúp đội ngũ cùng hướng về trải nghiệm khách hàng, niềm tin và tăng trưởng bền vững.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b9965f6f-f7ad-4f43-aa2c-772949930969','43ac912f-f861-4c25-a691-740a03914b96',69,'image',NULL,'book/06-stars-luong-thuong/9c21467e-34b2-463e-8f3b-9916285c37ca-img04.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('62475ca8-f141-49d2-8cc5-47336c83fa87','06-stars-luong-thuong','45326817-8c56-40a8-a695-433fad6ce16d',2,'Logic công bằng','logic-cong-bang',21,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cca4c525-7a6c-46ec-af05-a6145bb017af','62475ca8-f141-49d2-8cc5-47336c83fa87',70,'text','Cơ chế S.T.A.R.S tạo ra một dạng công bằng tương đối nhưng bền hơn công bằng cảm tính. Người lao động không chỉ được trả vì có mặt, mà còn vì giữ vai trò, giữ chuẩn, giữ nhịp làm việc, tạo ra kết quả và đóng góp cho tập thể.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cb251326-3b8b-4957-8d92-9ee5cc771009','62475ca8-f141-49d2-8cc5-47336c83fa87',71,'text','Cách thiết kế này giúp tránh hai thái cực phổ biến: một là chỉ trả theo thâm niên, hai là chỉ thưởng theo doanh thu. Trong môi trường y tế, cả hai thái cực đều có thể làm méo hành vi nếu không được kiểm soát bởi đạo đức, dữ liệu và trách nhiệm hệ thống.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e0afd9f2-58c2-4ac7-b309-25044cfc268f','06-stars-luong-thuong','45326817-8c56-40a8-a695-433fad6ce16d',2,'Cách hiểu ngắn gọn','cach-hieu-ngan-gon',22,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('94b2e978-ec60-4a67-9d75-03937d2f7d58','e0afd9f2-58c2-4ac7-b309-25044cfc268f',72,'text','Có thể hiểu ngắn gọn như sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f3993545-d0b6-4476-bb67-24807a68995d','e0afd9f2-58c2-4ac7-b309-25044cfc268f',73,'text','- **Lương cứng** = trả cho vai trò.- **Phụ cấp S.T** = trả cho năng lực ổn định.- **Thưởng A.R** = trả cho hành động và kết quả.- **Thưởng Hiệp lực** = trả cho đóng góp vào sức mạnh chung.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('48416d07-12f3-4b48-8a08-9753a357f99b','e0afd9f2-58c2-4ac7-b309-25044cfc268f',74,'text','Khi bốn lớp này được thiết kế đúng, S.T.A.R.S không chỉ là mô hình đánh giá nhân sự, mà trở thành một cơ chế vận hành con người có khả năng giữ công bằng, khuyến khích phát triển và bảo vệ văn hóa tử tế của phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0d1473b6-2dd7-4742-84b4-5885c33b5bf8','06-stars-luong-thuong','45326817-8c56-40a8-a695-433fad6ce16d',2,'Nguyên tắc vận hành lương thưởng','nguyen-tac-van-hanh-luong-thuong',23,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('449a8cfe-b8e7-4bab-9643-4990536f05e8','0d1473b6-2dd7-4742-84b4-5885c33b5bf8',75,'text','Lương thưởng theo S.T.A.R.S không chỉ là bài toán tài chính, mà trước hết là một **cơ chế quản trị hành vi**. Vì vậy, khi vận hành, phòng khám phải giữ nguyên tắc rõ ràng, minh bạch và nhất quán, để thu nhập trở thành công cụ phát triển con người chứ không phải nguồn gây nhiễu cho tổ chức.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4809c241-4cf1-4b63-92f4-02f9736c9aec','0d1473b6-2dd7-4742-84b4-5885c33b5bf8',76,'text','- Nguyên tắc đầu tiên là **rõ tiêu chí**. Mỗi phần thu nhập phải có lý do tồn tại, có điều kiện hưởng và có chỉ số đo cụ thể. Người lao động cần biết mình đang được trả cho điều gì, và phải làm gì để cải thiện phần thu nhập ấy.- Nguyên tắc thứ hai là **đo được bằng số liệu**. Càng những phần thưởng liên quan đến hành động, kết quả và hiệp lực thì càng phải gắn với dữ liệu, checklist, KPI hoặc báo cáo vận hành. Nếu không đo được, thu nhập sẽ dễ trượt về cảm tính và mất tính công bằng.- Nguyên tắc thứ ba là **gắn với mục tiêu tháng hoặc chu kỳ rõ ràng**. Lương thưởng không nên thay đổi theo cảm xúc của người quản lý từng ngày, mà cần được chốt theo chu kỳ đủ ổn định để đội ngũ có thể hiểu, theo dõi và điều chỉnh hành vi.- Nguyên tắc thứ tư là **không khuyến khích hành vi lệch chuẩn**. Mọi khoản thưởng đều phải được đặt dưới Integrity; nghĩa là không thưởng cho booking nếu tư vấn sai sự thật, không thưởng review nếu xin review sai thời điểm, không thưởng doanh thu nếu có làm dư hoặc làm sai chuyên môn, và không thưởng kết quả nếu nó được tạo ra bằng cách gây hại cho bệnh nhân hay tổ chức.- Nguyên tắc thứ năm là **không thay thế nhau một cách tùy tiện**. Lương cứng không thể thay cho phụ cấp S.T, phụ cấp S.T không thể thay cho thưởng A.R, và thưởng cá nhân không thể thay cho thưởng hiệp lực. Mỗi lớp thu nhập phải trả cho đúng bản chất của nó, nếu không hệ thống sẽ mất cấu trúc và sinh ra lệch hành vi.- Nguyên tắc thứ sáu là **xem lương thưởng như một phần của văn hóa**. Khi cơ chế đãi ngộ được thiết kế đúng, nó sẽ dạy đội ngũ cách làm việc đúng: giữ vai trò, giữ chất lượng, giữ kết quả và giữ sự phối hợp. Ngược lại, nếu lương thưởng thiết kế sai, nó sẽ vô tình dạy đội ngũ cách chạy số, né trách nhiệm hoặc tối ưu cá nhân thay vì tối ưu hệ thống.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e4b09729-25fc-41e8-a3da-905bfb3007a5','0d1473b6-2dd7-4742-84b4-5885c33b5bf8',77,'text','Nói gọn lại, nguyên tắc vận hành lương thưởng theo S.T.A.R.S là: **rõ ràng, đo được, công bằng tương đối, không lệch Integrity và khuyến khích phát triển bền vững**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('9c438800-401d-4f22-b828-c640ca9f48a2','06-stars-luong-thuong',NULL,1,'6.5 VỊ TRÍ S.T.A.R.S TRONG DENTAL EMPIRE OS','65-vi-tri-stars-trong-dental-empire-os',24,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ed4426d6-973e-48d7-a3ab-45482a75c70d','9c438800-401d-4f22-b828-c640ca9f48a2',78,'text','Trong kiến trúc tổng thể của Dental Empire OS, S.T.A.R.S là mô hình lõi của **Hệ điều hành con người**. Nếu Dental Empire OS trả lời câu hỏi phòng khám cần những hệ nào để tăng trưởng bền vững, thì S.T.A.R.S trả lời câu hỏi con người trong hệ ấy phải được quản trị theo chuẩn nào để toàn bộ hệ thống vận hành đúng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a6e50249-fb04-4132-803b-2ee51a34549f','9c438800-401d-4f22-b828-c640ca9f48a2',79,'image',NULL,'book/06-stars-luong-thuong/63f7eb99-02f6-4429-88f2-95ea385e92c7-img05.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2b91b460-892a-4138-b284-483177963567','06-stars-luong-thuong',NULL,1,'6.6 MÔ HÌNH DOANH THU - LỢI NHUẬN - LƯƠNG THƯỞNG','66-mo-hinh-doanh-thu-loi-nhuan-luong-thuong',25,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('6342147c-7d52-49e7-9494-b38d7e62b31a','06-stars-luong-thuong','2b91b460-892a-4138-b284-483177963567',2,'Định nghĩa','inh-nghia',26,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('fd5d3305-f90d-4031-9bcd-fa6f17bbad64','06-stars-luong-thuong','6342147c-7d52-49e7-9494-b38d7e62b31a',3,'1.1. Doanh thu thực thu','11-doanh-thu-thuc-thu',27,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1f1b58ad-b558-43dd-9a04-71bdc21e82da','fd5d3305-f90d-4031-9bcd-fa6f17bbad64',80,'text','Doanh thu thực thu là phần doanh thu phòng khám thực sự ghi nhận được từ các dịch vụ đã thanh toán hoặc đủ điều kiện ghi nhận, và cần được theo dõi theo dịch vụ cũng như theo nguồn khách.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('6e183507-7755-4004-99a5-bf9d26506559','06-stars-luong-thuong','6342147c-7d52-49e7-9494-b38d7e62b31a',3,'1.2. Tổng chi phí trước thưởng','12-tong-chi-phi-truoc-thuong',28,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6e66554d-b488-417e-995f-399cabfa99ff','6e183507-7755-4004-99a5-bf9d26506559',81,'text','Tổng chi phí trước thưởng là toàn bộ chi phí cần thiết để tạo ra doanh thu và vận hành phòng khám trước khi hình thành quỹ thưởng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d394e031-cca4-4bff-bc7f-251672f193df','6e183507-7755-4004-99a5-bf9d26506559',82,'text','Tổng chi phí trước thưởng bao gồm:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('484e6cfa-1c58-412b-9bc0-8a93fb998d6a','6e183507-7755-4004-99a5-bf9d26506559',83,'text','- Chi phí cố định: mặt bằng, phần mềm, khấu hao, điện nước, bảo trì.- Chi phí biến đổi: vật tư, lab, ads, quà tặng bệnh nhân và các chi phí tăng theo hoạt động.- Chi phí gắn theo doanh thu: hoa hồng tư vấn, chi phí bác sĩ theo ca hoặc theo phần trăm, chi phí phụ tá gắn với doanh thu hoặc case điều trị.- Chi phí nhân sự nền tảng: lương cứng và phụ cấp S.T, vì đây là khoản chi cho năng lực và độ tin cậy nền tảng của nhân sự, không phải thưởng chia từ quỹ lợi nhuận.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('cf981a7a-ab6d-4572-b2df-e41d7020e310','06-stars-luong-thuong','6342147c-7d52-49e7-9494-b38d7e62b31a',3,'1.3. Phụ cấp S.T','13-phu-cap-st',29,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f9232086-50ac-47b3-90f7-8ff676040d11','cf981a7a-ab6d-4572-b2df-e41d7020e310',84,'text','Phụ cấp S.T là khoản thu nhập nền tảng trả cho năng lực và độ tin cậy của nhân sự trong hệ S.T.A.R.S. Khoản này thuộc lớp chi phí nhân sự trước thưởng, không lấy từ quỹ A.R hoặc Synergy.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('866ec516-9bf6-4743-9a0b-ac11f0ec6564','06-stars-luong-thuong','6342147c-7d52-49e7-9494-b38d7e62b31a',3,'1.4. Lợi nhuận trước thưởng','14-loi-nhuan-truoc-thuong',30,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5efc7985-0b28-44c4-b0f5-3228d7ea73f0','866ec516-9bf6-4743-9a0b-ac11f0ec6564',85,'text','Lợi nhuận trước thưởng là phần lợi nhuận còn lại sau khi doanh thu thực thu đã trừ toàn bộ chi phí trước thưởng. Đây là phần nền để xem xét trích lập quỹ thưởng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f219159a-e1d3-4383-85cf-ad14e4d67491','06-stars-luong-thuong','6342147c-7d52-49e7-9494-b38d7e62b31a',3,'1.5. Quỹ thưởng','15-quy-thuong',31,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e79809cf-11aa-4228-8ee4-408fc3a3756e','f219159a-e1d3-4383-85cf-ad14e4d67491',86,'text','Quỹ thưởng là phần ngân sách được trích từ lợi nhuận trước thưởng để phân bổ cho thưởng A.R và thưởng Synergy theo chính sách từng kỳ.Thưởng A.RThưởng A.R là phần thu nhập trả cho hành động thực tế và kết quả đo lường được của từng cá nhân hoặc vai trò. Theo tài liệu S.T.A.R.S, thưởng A.R gồm thưởng hành động đúng, thưởng kết quả đạt, thưởng hiệu quả tốt và thưởng cải tiến hệ thống.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('27bc096c-2d8b-4a35-aa87-fa21760a300e','06-stars-luong-thuong','f219159a-e1d3-4383-85cf-ad14e4d67491',4,'Thưởng Synergy','thuong-synergy',32,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('dba8986b-0a83-4746-b526-cb6b36426a1d','27bc096c-2d8b-4a35-aa87-fa21760a300e',87,'text','Thưởng Synergy là phần thưởng dành cho kết quả chung và sự phối hợp giữa các bộ phận hoặc circle, nhằm khuyến khích đội ngũ tối ưu kết quả toàn hệ thống thay vì chỉ tối ưu lợi ích cá nhân.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('6377d8f5-9311-4cfa-a842-e0276f67a703','06-stars-luong-thuong','6342147c-7d52-49e7-9494-b38d7e62b31a',3,'1.6. Lợi nhuận giữ lại','16-loi-nhuan-giu-lai',33,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a4387f62-a859-406a-b95f-f8d2c820c281','6377d8f5-9311-4cfa-a842-e0276f67a703',88,'text','Lợi nhuận giữ lại là phần lợi nhuận còn lại sau khi đã trích và chi quỹ thưởng, được dùng cho dự phòng dòng tiền, tái đầu tư, mở rộng hệ thống hoặc phân phối cho chủ sở hữu theo chính sách tài chính riêng của phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ff732733-5695-4083-be9e-ba31fc875b38','06-stars-luong-thuong','2b91b460-892a-4138-b284-483177963567',2,'Công thức','cong-thuc',34,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b3d5ffb8-74cf-4923-878a-b436f49ee586','06-stars-luong-thuong','ff732733-5695-4083-be9e-ba31fc875b38',3,'2.1. Công thức tổng thể','21-cong-thuc-tong-the',35,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('904f8d4e-da12-46ce-9de7-85f034b5e72d','b3d5ffb8-74cf-4923-878a-b436f49ee586',89,'image',NULL,'book/06-stars-luong-thuong/718c1505-ce9b-4c0e-8ad8-19541c364daa-img06.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('6b932cc8-4b48-433b-9df1-701c2c9c984a','06-stars-luong-thuong','ff732733-5695-4083-be9e-ba31fc875b38',3,'2.2. Công thức thu nhập nhân sự','22-cong-thuc-thu-nhap-nhan-su',36,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ce0603e0-7444-4b52-aca1-9a137e06870e','6b932cc8-4b48-433b-9df1-701c2c9c984a',90,'text','Tổng thu nhập nhân sự = Lương cứng + Phụ cấp S.T + Khoản % hoặc commission nếu có + Thưởng A.R + Thưởng Synergy.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('493ceae4-f7e8-47a7-b0f8-e0c023edae06','06-stars-luong-thuong','ff732733-5695-4083-be9e-ba31fc875b38',3,'2.3. Bản công thức rút gọn theo dòng tiền','23-ban-cong-thuc-rut-gon-theo-dong-tien',37,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2bdb0d22-de83-4d95-a135-59a444813f23','493ceae4-f7e8-47a7-b0f8-e0c023edae06',91,'image',NULL,'book/06-stars-luong-thuong/0d44248e-78aa-4280-8202-7f55b9fd7df9-img07.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('38294dee-ea85-447a-a90c-6f2efe779ba7','06-stars-luong-thuong','2b91b460-892a-4138-b284-483177963567',2,'Nguyên tắc','nguyen-tac',38,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('c73e17fd-7c8f-4c34-b794-d879196a6c6c','06-stars-luong-thuong','38294dee-ea85-447a-a90c-6f2efe779ba7',3,'3.1. Nguyên tắc ghi nhận doanh thu','31-nguyen-tac-ghi-nhan-doanh-thu',39,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('92ead8bc-bf6c-4ca7-bb63-58cb70e28e75','c73e17fd-7c8f-4c34-b794-d879196a6c6c',92,'text','- Doanh thu phải được ghi nhận theo dịch vụ và theo nguồn khách.- Không đánh giá hiệu quả chỉ bằng doanh thu tổng, vì Finance OS yêu cầu nhìn đồng thời cả chi phí, lợi nhuận và ROI.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('4479592d-abf9-41ad-8de3-d2ec156189ec','06-stars-luong-thuong','38294dee-ea85-447a-a90c-6f2efe779ba7',3,'3.2. Nguyên tắc ghi nhận chi phí','32-nguyen-tac-ghi-nhan-chi-phi',40,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c48cc8e9-b095-43a6-be23-c145ec082c07','4479592d-abf9-41ad-8de3-d2ec156189ec',93,'text','- Mọi khoản chi phí phải được ghi nhận rõ, minh bạch và có thể kiểm soát bằng số liệu.- Khoản % hoa hồng, chi phí bác sĩ theo ca và chi phí phụ tá gắn với doanh thu được xem là chi phí trước thưởng, không phải quỹ thưởng.- Phụ cấp S.T là chi phí nhân sự nền tảng, không lấy từ quỹ thưởng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ef4c2d0e-b956-4258-9273-c77d7d9ca052','06-stars-luong-thuong','38294dee-ea85-447a-a90c-6f2efe779ba7',3,'3.3. Nguyên tắc trích quỹ thưởng','33-nguyen-tac-trich-quy-thuong',41,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d33145ef-5ac3-4874-acb5-6844954d3e2f','ef4c2d0e-b956-4258-9273-c77d7d9ca052',94,'text','- Chỉ trích quỹ thưởng sau khi đã xác định lợi nhuận trước thưởng.- A.R là thưởng cho hành động và kết quả cá nhân đo được.- Synergy là thưởng cho kết quả phối hợp chung của đội nhóm hoặc toàn phòng khám.- Quỹ thưởng không thay thế lương cứng, phụ cấp S.T hoặc các khoản chi phí vận hành.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('846d74ac-3902-4186-a860-a8a689d1aa34','06-stars-luong-thuong','38294dee-ea85-447a-a90c-6f2efe779ba7',3,'3.4 Ba vùng doanh thu','34-ba-vung-doanh-thu',42,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c67ca791-fddd-44e2-b8fa-64e787d0c039','846d74ac-3902-4186-a860-a8a689d1aa34',95,'image',NULL,'book/06-stars-luong-thuong/2e6b62af-5dd7-4b45-8096-5c9486e07e48-img08.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('6ac7202d-727b-45d0-a8cc-d05011cf39cc','06-stars-luong-thuong','38294dee-ea85-447a-a90c-6f2efe779ba7',3,'3.5 Nguyên tắc ONE LIGHT','35-nguyen-tac-one-light',43,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('45b6836e-a2d1-4aef-baf9-65e2dbac969f','6ac7202d-727b-45d0-a8cc-d05011cf39cc',96,'text','- Không thưởng cho kết quả tạo ra bằng hành vi sai ONE LIGHT như tư vấn sai, làm dư, ép review hoặc ghi nhận sai số liệu.- Số liệu tài chính, KPI và lương thưởng phải minh bạch, chính xác và không bị chỉnh sửa tùy tiện.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('de8156e3-4872-4781-8011-17642127da3c','06-stars-luong-thuong','38294dee-ea85-447a-a90c-6f2efe779ba7',3,'3.6. Nguyên tắc giữ lại lợi nhuận','36-nguyen-tac-giu-lai-loi-nhuan',44,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3c9eb550-8435-42a0-a418-3b821cb15295','de8156e3-4872-4781-8011-17642127da3c',97,'text','- Phòng khám cần giữ lại một phần lợi nhuận sau thưởng để dự phòng dòng tiền và tái đầu tư, vì Finance OS nhấn mạnh kiểm soát dòng tiền, công nợ và năng lực mở rộng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('045fda9f-94c7-4b8f-ae61-8f71ae69f436','06-stars-luong-thuong','38294dee-ea85-447a-a90c-6f2efe779ba7',3,'3.7 Ví dụ minh họa bằng số','37-vi-du-minh-hoa-bang-so',45,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('eb5b22bd-3943-40e8-80ab-a1c19fae39e0','045fda9f-94c7-4b8f-ae61-8f71ae69f436',98,'text','Giả sử trong một tháng, phòng khám có các số liệu sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0e2cb1b1-27d4-4724-a229-f63b64238a27','045fda9f-94c7-4b8f-ae61-8f71ae69f436',99,'text','- Doanh thu thực thu: 1.000.000.000 đồng.- Chi phí cố định: 180.000.000 đồng.- Chi phí biến đổi: 120.000.000 đồng.- Chi phí gắn theo doanh thu, gồm hoa hồng, bác sĩ theo ca, phụ tá theo doanh thu hoặc case: 200.000.000 đồng.- Chi phí nhân sự nền tảng, gồm lương cứng và phụ cấp S.T: 220.000.000 đồng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d01b9583-6387-4790-a895-3851614ae71c','045fda9f-94c7-4b8f-ae61-8f71ae69f436',100,'text','Khi đó:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8e9406cb-a05e-4e2b-99a1-4660c03f7943','045fda9f-94c7-4b8f-ae61-8f71ae69f436',101,'text','Tổng chi phí trước thưởng = 180.000.000 + 120.000.000 + 200.000.000 + 220.000.000 = 720.000.000 đồng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c7910925-13ed-4000-aff9-0b454904a0f5','045fda9f-94c7-4b8f-ae61-8f71ae69f436',102,'text','Lợi nhuận trước thưởng = 1.000.000.000 - 720.000.000 = 280.000.000 đồng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c7678907-5c1f-4433-aef6-4e6f57f6bdf7','045fda9f-94c7-4b8f-ae61-8f71ae69f436',103,'text','Giả sử phòng khám quyết định trích:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('76c993ec-fecb-4411-9a55-84bd638d8b2a','045fda9f-94c7-4b8f-ae61-8f71ae69f436',104,'text','- Quỹ thưởng A.R: 80.000.000 đồng.- Quỹ thưởng Synergy: 40.000.000 đồng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('702c5cc8-8b03-463d-8284-50763203846d','045fda9f-94c7-4b8f-ae61-8f71ae69f436',105,'text','Khi đó:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a37b9827-1808-49e4-9ca9-ad89b5c66092','045fda9f-94c7-4b8f-ae61-8f71ae69f436',106,'text','Lợi nhuận giữ lại = 280.000.000 - 80.000.000 - 40.000.000 = 160.000.000 đồng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2a9eca71-e3f0-40bc-9f19-38019c01af07','045fda9f-94c7-4b8f-ae61-8f71ae69f436',107,'text','Diễn giải:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e3380e6e-1637-4a33-918c-d91da63e7da0','045fda9f-94c7-4b8f-ae61-8f71ae69f436',108,'text','- 720.000.000 đồng là phần chi phí cần thiết để tạo ra doanh thu và giữ hệ thống vận hành.- 280.000.000 đồng là phần lợi nhuận trước thưởng, tức phần đủ điều kiện xem xét phân bổ thưởng.- 120.000.000 đồng được trích làm quỹ thưởng hiệu suất, trong đó A.R trả cho cá nhân và Synergy trả cho kết quả phối hợp chung.- 160.000.000 đồng còn lại là phần lợi nhuận giữ lại cho dự phòng, tái đầu tư hoặc phân phối theo chính sách tài chính.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('903919f4-054f-4166-9223-c8a7a84a115c','06-stars-luong-thuong','38294dee-ea85-447a-a90c-6f2efe779ba7',3,'3.8 Giới hạn an toàn (CAP)','38-gioi-han-an-toan-cap',46,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('44d4d175-0afc-4896-9e78-e59d70e33061','903919f4-054f-4166-9223-c8a7a84a115c',109,'image',NULL,'book/06-stars-luong-thuong/a4b61e75-73f1-4229-9ccc-dafaee4a2076-img09.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('d6e4a65c-4a7e-4007-bb67-fa5d30834553','06-stars-luong-thuong','2b91b460-892a-4138-b284-483177963567',2,'Cấu trúc thu nhập nhân sự theo STARS','cau-truc-thu-nhap-nhan-su-theo-stars',47,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('85554f6c-d113-426a-bdfe-b0588834de28','d6e4a65c-4a7e-4007-bb67-fa5d30834553',110,'text','**THU NHẬP = LƯƠNG CỨNG + PHỤ CẤP P S.T + THƯỞNG A.R + SYNERGY CÁ NHÂN + PHỤ CẤP KHÁC**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('70275a6b-0213-4528-ad6a-061a8f68527a','d6e4a65c-4a7e-4007-bb67-fa5d30834553',111,'text','Cấu trúc này bảo đảm nhân sự được trả cho nền vai trò, năng lực, tố chất, mức độ thực thi, kết quả tạo ra và đóng góp hiệp lực vào kết quả chung của Circle. ONE LIGHT Circle không phải là một khoản thu nhập riêng, mà là điều kiện mở quỹ để phân bổ phần Synergy cá nhân.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ddf9348d-8c5d-421d-8fcf-c748ca9a1bb8','d6e4a65c-4a7e-4007-bb67-fa5d30834553',112,'image',NULL,'book/06-stars-luong-thuong/ab006f53-02c3-4c24-9ae7-11aa0edb5ce1-img10.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ebf56ae6-a2fa-4001-b853-6f57366fb6bc','06-stars-luong-thuong','d6e4a65c-4a7e-4007-bb67-fa5d30834553',3,'4.1 Nội dung từng khối','41-noi-dung-tung-khoi',48,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8f3f540e-e081-4b47-a4d1-8419ba0f9de5','ebf56ae6-a2fa-4001-b853-6f57366fb6bc',113,'text','- **LƯƠNG CỨNG: **Chi trả theo mức lương cơ bản cố định hằng tháng cho từng vị trí, phản ánh vai trò, trách nhiệm nền và sự hiện diện ổn định trong hệ thống. Mức lương này là lương theo vị trí mà thị trường đang trả ở mức cơ bản cho thời gian mà nhân sự làm việc hoặc kết quả đầu ra tối thiểu.- **THƯỞNG P S.T: ****Skills → Phụ Cấp**Đây là phần trả cho năng lực chuyên môn, tay nghề và độ chính xác khi làm việc; tức là người có kỹ năng tốt sẽ được cộng thêm vào thu nhập nền. Phần này có thể trả cho bằng cấp, thâm niên.- **Traits → Phụ cấp**Đây là phần trả cho tố chất ổn định như kỷ luật, trách nhiệm, cẩn trọng, chủ động; tức là không chỉ biết làm mà còn làm đáng tin cậy. Phần này có thể gồm: thâm niên, lãnh đạo, quản lý, lãnh thêm công việc.- **THƯỞNG A.R: ****Actions → thưởng A.R** Đây là phần thưởng cho mức độ thực thi hằng ngày: có làm đều, làm thật, làm đủ checklist, có theo sát công việc hay không. Phần này được theo dõi bằng phần mềm quản lý công việc, dự án.- **Results → Thưởng A.R**Đây là phần thưởng theo đầu ra đo được như doanh thu, chuyển đổi, tái khám, hiệu suất, chất lượng vận hành. Phần này được dựa trên KPI.- **THƯỞNG SYNERGY CÁ NHÂN: **Chi trả cho phần đóng góp hiệp lực của từng cá nhân vào kết quả chung của Tổ chức (Theo Cirle - Phòng ban), bao gồm phối hợp nội bộ, hỗ trợ đồng đội, giảm lỗi bàn giao, tăng trải nghiệm khách hàng và làm hệ thống mạnh lên. Phần thưởng này không được mở tự động, mà chỉ được phân bổ sau khi Circle mở được quỹ thưởng theo ONE LIGHT Circle- **PHỤ CẤP KHÁC: **Bao gồm các khoản phụ cấp theo chính sách công ty như điện thoại, đi lại, ăn trưa, công tác, thiết bị hoặc các hỗ trợ vận hành khác theo từng giai đoạn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('8fda25b6-b96d-448c-8667-d2b2d50a40ca','06-stars-luong-thuong','d6e4a65c-4a7e-4007-bb67-fa5d30834553',3,'4.2 ONE LIGHT CIRCLE','42-one-light-circle',49,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9479a25e-20a4-48da-82ab-514b07e4d516','8fda25b6-b96d-448c-8667-d2b2d50a40ca',114,'text','Là chỉ số tuân thủ tập thể của Circle, được tính theo thang 0.0 đến 1.0 để phản ánh mức độ đi đúng chuẩn hành vi, trách nhiệm, phối hợp và văn hóa vận hành của cả đội. ONE LIGHT Circle không phải là một khoản thưởng riêng, mà là cơ chế xác định Circle được mở bao nhiêu phần trăm quỹ thưởng chung.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('57d79e55-7deb-4a39-a52e-5313a478e5ee','8fda25b6-b96d-448c-8667-d2b2d50a40ca',115,'text','Cơ chế mở quỹ',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ddaf45ea-fd51-41a6-84bc-2c710c6c81e8','8fda25b6-b96d-448c-8667-d2b2d50a40ca',116,'text','**QUỸ MỞ = QUỸ THƯỞNG GỐC CỦA CIRCLE × TRUNG BÌNH TỈ TRỌNG ONE LIGHT CIRCLE**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e5a087a7-f536-4630-ad10-957a78683c66','8fda25b6-b96d-448c-8667-d2b2d50a40ca',117,'text','Nếu ONE LIGHT Circle đạt 1.0, Circle được mở 100% quỹ thưởng. Nếu ONE LIGHT Circle thấp hơn 1.0, Circle chỉ được mở phần quỹ tương ứng; phần còn lại bị giữ lại và xử lý theo policy nội bộ đã công bố trước.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5f737599-7156-4226-a2ff-a66a6254d103','06-stars-luong-thuong','d6e4a65c-4a7e-4007-bb67-fa5d30834553',3,'4.3 Cách đọc theo logic hệ thống','43-cach-oc-theo-logic-he-thong',50,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b31d3b74-730f-45b7-8da8-98b2f4fad7b4','5f737599-7156-4226-a2ff-a66a6254d103',118,'text','Mô hình này tách rõ 3 lớp:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4331484c-be07-46cf-9b71-177cf2cfe0aa','5f737599-7156-4226-a2ff-a66a6254d103',119,'text','- **Nền năng lực**- **Nền hành vi**- **Nền đạo đức**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('09ea75be-c457-4c7d-99df-3254753a5b2b','5f737599-7156-4226-a2ff-a66a6254d103',120,'text','Kỹ năng và tố chất tạo ra mức phụ cấp nền',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a5d7f14d-ed96-45c2-a743-0f86e77c3952','5f737599-7156-4226-a2ff-a66a6254d103',121,'text','Hành động và kết quả tạo ra thưởng theo hiệu suất',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('718c4ca0-3c72-4516-801c-8c87b75ced73','5f737599-7156-4226-a2ff-a66a6254d103',122,'text','Hiệp lực tạo ra thưởng hệ thống.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a03e10f5-a3e6-4a0f-b765-990a6b77d9ff','5f737599-7156-4226-a2ff-a66a6254d103',123,'image',NULL,'book/06-stars-luong-thuong/e4db6490-8b33-4241-b39d-94286ad3cd14-img11.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ac473567-b518-45a2-841f-ee2dfc928541','5f737599-7156-4226-a2ff-a66a6254d103',124,'text','***Ví dụ dễ hiểu:***',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6a330dc0-cf92-4bac-bc8c-6c0c6dd8646f','5f737599-7156-4226-a2ff-a66a6254d103',125,'text','Một bác sĩ có tay nghề tốt nhưng ít phối hợp với team thì vẫn có thể được hưởng **Skills/Traits**, nhưng phần **Synergy** sẽ thấp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9bd6daa9-aae2-49a6-9ada-6a938fca45aa','5f737599-7156-4226-a2ff-a66a6254d103',126,'text','Một tư vấn viên làm việc rất chăm, chốt tốt, nhưng nếu sai lệch về trung thực hoặc làm méo dữ liệu thì ONE LIGHT có thể khóa thưởng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6f8a5345-8a37-4bf7-8a93-612507193a83','5f737599-7156-4226-a2ff-a66a6254d103',127,'text','Ngược lại, một người chưa quá xuất sắc về kỹ năng nhưng kỷ luật tốt, phối hợp tốt và tạo kết quả tốt vẫn có thể nhận thu nhập cao hơn nhờ tổng hợp nhiều trụ cột.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3720237c-e5ea-42ed-9687-3e9f8d43effa','06-stars-luong-thuong','d6e4a65c-4a7e-4007-bb67-fa5d30834553',3,'4.4 Điểm mạnh của cách chia này','44-iem-manh-cua-cach-chia-nay',51,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('13eb9da3-9623-4302-b022-16a268179401','3720237c-e5ea-42ed-9687-3e9f8d43effa',128,'text','- Cách thiết kế này tránh được việc chỉ thưởng cho người “nói hay” hoặc chỉ thưởng cho người “ra số” mà bỏ qua chất lượng.- Nó cũng giúp phòng khám cân bằng giữa chuyên môn, hiệu suất và văn hóa, thay vì để một tiêu chí duy nhất điều khiển toàn bộ thu nhập.- Quan trọng nhất, **Integrity** giữ cho mô hình tài chính không tách rời đạo đức nghề nghiệp và trải nghiệm người bệnh.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7d7a60e1-617b-4a8a-8b34-491898ab7de9','3720237c-e5ea-42ed-9687-3e9f8d43effa',129,'text','**Skills và Traits được phản ánh qua phụ cấp; **',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('163bc3f6-7c5b-4d5c-9d0c-ce9f06457459','3720237c-e5ea-42ed-9687-3e9f8d43effa',130,'text','**Actions và Results được phản ánh qua thưởng A.R; **',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('36c8398f-2f61-4530-9aff-e19aebbebcfd','3720237c-e5ea-42ed-9687-3e9f8d43effa',131,'text','**Synergy được phản ánh qua thưởng Circle; **',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ae039871-c0d5-4540-96c9-1f546963da20','3720237c-e5ea-42ed-9687-3e9f8d43effa',132,'text','**ONE LIGHT là điều kiện mở hoặc khóa để bảo đảm mọi khoản chi trả đều nằm trong chuẩn đạo đức và chuẩn vận hành của hệ thống**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2c2ce8e5-95dd-4927-87d5-72376d1d66f0','3720237c-e5ea-42ed-9687-3e9f8d43effa',133,'text','Lương cứng là **phần thu nhập cố định trả cho vị trí và trách nhiệm nền tảng của một role**, tách biệt với phần trả cho năng lực, hành động, kết quả và hiệp lực trong S.T.A.R.S. Trong cấu trúc thu nhập của mô hình, lương cứng là “nền vai trò”, còn các phần biến động mới là nơi ghi nhận khác biệt về đóng góp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('42cba1b4-ae99-4f18-9efa-2aec67cdd1d9','06-stars-luong-thuong','2b91b460-892a-4138-b284-483177963567',2,'Lương cứng là gì?','luong-cung-la-gi',52,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6a7b38a7-1b20-4f7b-9e53-540742c9f4e5','42cba1b4-ae99-4f18-9efa-2aec67cdd1d9',134,'text','Lương cứng không phải là phần thưởng cho người làm tốt nhất, mà là khoản trả để một người **giữ đúng vai trò và hiện diện ổn định trong hệ thống**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b9121397-4cca-4a8a-982b-9d7cbfa66774','42cba1b4-ae99-4f18-9efa-2aec67cdd1d9',135,'text','Nó gắn với vị trí công việc, phạm vi trách nhiệm cơ bản và sự ổn định vận hành, nên dùng để bảo đảm người đó có một mức thu nhập chắc chắn mỗi tháng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b530b1fa-d79d-40e3-bc0e-bbb902e1ee00','42cba1b4-ae99-4f18-9efa-2aec67cdd1d9',136,'text','Vì vậy, lương cứng là phần “đứng yên” của thu nhập, còn S/T , A/R và Synergy là phần “động”.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3f47cb0a-b8e7-4311-b4e7-06eff86d2935','06-stars-luong-thuong','42cba1b4-ae99-4f18-9efa-2aec67cdd1d9',3,'5.1 Vì sao cần lương cứng','51-vi-sao-can-luong-cung',53,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fbae9d34-1505-492d-b6af-1625eecc57b3','3f47cb0a-b8e7-4311-b4e7-06eff86d2935',137,'text','Trong phòng khám, nếu không có lương cứng rõ ràng thì nhân sự dễ bị cảm giác bấp bênh, còn tổ chức thì dễ trượt sang trả lương hoàn toàn theo doanh số hoặc cảm tính.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('be8a7c54-5fe1-4175-9afa-05f3087e5201','3f47cb0a-b8e7-4311-b4e7-06eff86d2935',138,'text','S.T.A.R.S chủ trương tránh hai cực đoan: chỉ trả theo thâm niên hoặc chỉ trả theo doanh thu, vì cả hai đều dễ tạo méo mó hành vi.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6bdadece-e7e2-4c24-a694-5c3a49437e32','3f47cb0a-b8e7-4311-b4e7-06eff86d2935',139,'text','Do đó, lương cứng đóng vai trò giữ người, giữ vai, và giữ sự ổn định tối thiểu để hệ thống vận hành được.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('24a7d439-4a29-4ec6-8753-730272b1fde5','06-stars-luong-thuong','42cba1b4-ae99-4f18-9efa-2aec67cdd1d9',3,'5.2 Lương cứng được tính theo gì?','52-luong-cung-uoc-tinh-theo-gi',54,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d14cd6a0-b36a-4708-8273-28f30b09f755','24a7d439-4a29-4ec6-8753-730272b1fde5',140,'image',NULL,'book/06-stars-luong-thuong/45f52f8f-09c0-43bf-a95f-f13aaf98d2ad-img12.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a4406ee6-d998-4be8-b84b-8844b147e190','24a7d439-4a29-4ec6-8753-730272b1fde5',141,'text','Lương cứng nên được thiết lập dựa trên 4 yếu tố chính:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7f963b7a-dcb2-4457-8f6e-1f997d05bd64','24a7d439-4a29-4ec6-8753-730272b1fde5',142,'text','- Số giờ làm việc hoặc cường độ hiện diện theo thỏa thuận.- Trách nhiệm cơ bản phải gánh.- Chuẩn năng lực tối thiểu để làm đúng vai trò.- Chuẩn hành vi tối thiểu để vận hành ổn định trong hệ thống.- Tham chiếu thị trường và ngân sách của phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('142d5904-0ccc-4012-8c42-d62641e4320e','24a7d439-4a29-4ec6-8753-730272b1fde5',143,'text','Cách hiểu ngắn gọn là: role càng quan trọng, càng khó thay thế, hoặc yêu cầu trách nhiệm nền càng cao thì lương cứng càng lớn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('06aa6286-b455-464c-9308-bf22d77fe53e','24a7d439-4a29-4ec6-8753-730272b1fde5',144,'text','Tuy nhiên, lương cứng vẫn phải là một con số cố định, dễ hiểu, và không phụ thuộc vào biến động hiệu suất tháng đó.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('84b6ee83-0b7d-41c2-bb97-03468e4dd59d','06-stars-luong-thuong','42cba1b4-ae99-4f18-9efa-2aec67cdd1d9',3,'5.3 Lương cứng không phải là gì','53-luong-cung-khong-phai-la-gi',55,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1b1503e4-779b-4c7e-812e-011290efcca7','84b6ee83-0b7d-41c2-bb97-03468e4dd59d',145,'text','Lương cứng **không** phải là:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('344ff243-77d9-4c5e-ba9c-c0b01c8b0ca1','84b6ee83-0b7d-41c2-bb97-03468e4dd59d',146,'text','- Toàn bộ thu nhập của nhân sự.- Phần thưởng cho kết quả xuất sắc.- Tiền trả cho hành động vượt chuẩn.- Khoản chia cho phối hợp đội nhóm.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('08738ce6-3f15-4ef7-8d01-1e2f8a8ba338','84b6ee83-0b7d-41c2-bb97-03468e4dd59d',147,'text','Những phần này được tách sang các lớp khác của S.T.A.R.S:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d40914f8-c2f0-406d-8ced-289b206b031e','84b6ee83-0b7d-41c2-bb97-03468e4dd59d',148,'text','- **S.T** trả cho nền năng lực và độ tin cậy.- **A.R** trả cho hành động và kết quả đo được.- **Synergy** trả cho hiệp lực và đóng góp cho hệ thống.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('4e83291a-f7ca-460f-843f-ea732d06358c','06-stars-luong-thuong','42cba1b4-ae99-4f18-9efa-2aec67cdd1d9',3,'5.4 Cấu trúc thu nhập','54-cau-truc-thu-nhap',56,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('11667e1b-cb58-4155-bc5d-ac0d330c6e52','4e83291a-f7ca-460f-843f-ea732d06358c',149,'text','Trong mô hình, công thức tổng quát là:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b4452616-8ff9-49bb-9bd8-bc02332b901f','4e83291a-f7ca-460f-843f-ea732d06358c',150,'text','**Thu nhập = Lương cứng + Phụ cấp S.T + Thưởng A.R + Thưởng Hiệp lực**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bbab3910-50d4-48ee-aed2-a478dd67f632','4e83291a-f7ca-460f-843f-ea732d06358c',151,'text','Nhìn theo logic này:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e0274e7a-c305-45d0-b3c9-7e53345a820c','4e83291a-f7ca-460f-843f-ea732d06358c',152,'text','- Lương cứng = trả cho vai trò.- Phụ cấp S.T = trả cho năng lực và tố chất.- Thưởng A.R = trả cho thực thi và kết quả.- Thưởng Hiệp lực = trả cho phối hợp và sức mạnh tập thể.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('16bcb0d1-780d-4cb3-b49d-38a2c0fbd40c','06-stars-luong-thuong','42cba1b4-ae99-4f18-9efa-2aec67cdd1d9',3,'5.5 Cách thiết lập thực tế','55-cach-thiet-lap-thuc-te',57,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('da4aa2fe-ea48-48ed-b71f-bbf2022ce81e','16bcb0d1-780d-4cb3-b49d-38a2c0fbd40c',153,'text','Một cách triển khai dễ dùng cho phòng khám là:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ace10295-68be-416f-9f8f-083bd89a5983','16bcb0d1-780d-4cb3-b49d-38a2c0fbd40c',154,'text','- Viết rõ role card cho từng vị trí.- Chốt trách nhiệm nền tảng của role đó.- Xác định một mức lương cứng cố định theo mặt bằng thị trường.- Rà soát lại định kỳ, thường là 6–12 tháng một lần.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f3bdfc81-c8c7-4536-a1c4-930559d5da4f','16bcb0d1-780d-4cb3-b49d-38a2c0fbd40c',155,'text','Cách này giúp lương cứng không bị biến thành “mặc cả cảm tính”, mà trở thành một chính sách quản trị rõ ràng.
Khi role thay đổi hoặc phạm vi trách nhiệm tăng lên, lương cứng cũng có thể được điều chỉnh tương ứng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('4861f4d1-596c-4f0a-9c47-c6a070abd2fc','06-stars-luong-thuong','42cba1b4-ae99-4f18-9efa-2aec67cdd1d9',3,'5.6 Khi nào là tăng lương cứng','56-khi-nao-la-tang-luong-cung',58,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9ab22100-20bc-421e-8bb1-c3e55c7b38b3','4861f4d1-596c-4f0a-9c47-c6a070abd2fc',156,'text','Tăng lương định kỳ nên được xem là tăng lương cứng nếu:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e773905a-3532-4eec-9357-c1270a60f333','4861f4d1-596c-4f0a-9c47-c6a070abd2fc',157,'text','- Role đã lớn hơn trước.- Trách nhiệm nền tăng lên.- Mức độ thay thế của vị trí cao hơn.- Nhân sự đã đạt ngưỡng ổn định mới về năng lực và độ tin cậy.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c9e62a4b-b9a8-4f0e-9406-7228e6b3a4f0','4861f4d1-596c-4f0a-9c47-c6a070abd2fc',158,'text','Ví dụ: lễ tân từ việc chỉ nhận khách và đặt lịch, chuyển sang vừa quản lý CRM, vừa theo dõi tái khám, vừa chịu trách nhiệm inbox/call thì mức lương cứng có thể được điều chỉnh tăng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1f1dab43-6ad7-4208-954d-ec49bd03e51d','06-stars-luong-thuong','42cba1b4-ae99-4f18-9efa-2aec67cdd1d9',3,'5.7 Khi nào không phải tăng lương cứng','57-khi-nao-khong-phai-tang-luong-cung',59,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9d373db7-fe7f-4e62-bb6f-e496714101d8','1f1dab43-6ad7-4208-954d-ec49bd03e51d',159,'text','Không phải tăng lương cứng nếu:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('11843cc3-35b1-4c64-9400-f2070c681166','1f1dab43-6ad7-4208-954d-ec49bd03e51d',160,'text','- Chỉ thưởng theo kết quả tháng.- Chỉ cộng thêm phụ cấp tạm thời.- Chỉ chi trả cho chiến dịch ngắn hạn.- Chỉ tăng theo cảm tính, không đổi trách nhiệm role.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('02993a82-79f8-4b50-a348-e91504208a9d','1f1dab43-6ad7-4208-954d-ec49bd03e51d',161,'text','Nói ngắn gọn: **tăng tiền nhưng không tăng nền vai trò thì chưa gọi là tăng lương cứng**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1f2e0a01-64b7-4e3d-8e9c-5fa545e3d2c9','1f1dab43-6ad7-4208-954d-ec49bd03e51d',162,'text','**Ví dụ dễ hiểu**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('daa408fc-744b-423b-af5d-e715c8b77b61','1f1dab43-6ad7-4208-954d-ec49bd03e51d',163,'text','Ví dụ một lễ tân trong phòng khám có nhiệm vụ:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('88ab6fe9-07f8-48f4-922d-b491ba6b50c3','1f1dab43-6ad7-4208-954d-ec49bd03e51d',164,'text','- Đón tiếp khách.- Phản hồi inbox/call.- Đặt lịch.- Nhắc lịch.- Hỗ trợ CRM.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('50fbb98e-e9e3-4124-b089-3e0166516839','1f1dab43-6ad7-4208-954d-ec49bd03e51d',165,'text','Lương cứng của vị trí này sẽ là khoản cố định để trả cho việc giữ vai trò lễ tân và bảo đảm vận hành nền mỗi ngày.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('03451aee-b4da-469b-a453-230d120a698b','1f1dab43-6ad7-4208-954d-ec49bd03e51d',166,'text','Nếu lễ tân làm tốt hơn, phần tăng thêm sẽ đi vào S.T, A.R. hoặc Synergy, chứ không bắt lương cứng phải “gánh” hết mọi giá trị.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ca8439c3-3ad4-4400-a028-acb80a35567f','06-stars-luong-thuong','42cba1b4-ae99-4f18-9efa-2aec67cdd1d9',3,'5.8 Chính sách gợi ý','58-chinh-sach-goi-y',60,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bbabfc26-a116-40e2-b7af-58dc1f53e545','ca8439c3-3ad4-4400-a028-acb80a35567f',167,'text','Lương cứng là phần thu nhập cố định trả cho vị trí, trách nhiệm nền tảng và sự ổn định của nhân sự trong hệ thống. Lương cứng được xác định theo role card (vai trò), tham chiếu thị trường và ngân sách phòng khám; các phần ghi nhận năng lực, hành động, kết quả và hiệp lực sẽ được phân bổ riêng theo S.T.A.R.S.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3c8a0114-7992-4ee8-904a-92e43a261ccd','ca8439c3-3ad4-4400-a028-acb80a35567f',168,'text','Dưới đây là bản viết lại có thể đưa thẳng vào handbook/policy. Bản này giữ đúng logic của S.T.A.R.S: lương cứng trả cho **nền vai trò**, phụ cấp S.T trả cho **mức vượt chuẩn về kỹ năng và tố chất**, còn tăng lương cứng chỉ xảy ra khi nhân sự đạt ngưỡng mới và được giao **vai trò/trách nhiệm cao hơn**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b0f4024b-a37c-469e-b78d-ed1fffdb8933','06-stars-luong-thuong','2b91b460-892a-4138-b284-483177963567',2,'Phụ cấp S.T là gì?','phu-cap-st-la-gi',61,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2cabc67a-9998-438e-88e5-6f76cbb7ee37','b0f4024b-a37c-469e-b78d-ed1fffdb8933',169,'image',NULL,'book/06-stars-luong-thuong/8da96516-3a60-4fce-9054-005bb70309bd-img13.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('437af371-8726-45b1-9467-a416108f6f1c','06-stars-luong-thuong','b0f4024b-a37c-469e-b78d-ed1fffdb8933',3,'Nguyên tắc chung','nguyen-tac-chung',62,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('76858963-da64-416e-8525-c2f274db049b','437af371-8726-45b1-9467-a416108f6f1c',170,'text','Trong hệ thống đãi ngộ của phòng khám, **lương cứng** là khoản thu nhập trả cho **nền vai trò**, bao gồm vị trí công việc, thời gian hiện diện, trách nhiệm cơ bản và mức năng lực tối thiểu cần có để giữ vai trò đó.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0d2e1d0d-af6b-4783-8d45-9acba94ac920','437af371-8726-45b1-9467-a416108f6f1c',171,'text','**Phụ cấp S.T** là khoản cộng thêm trên nền lương cứng, dùng để ghi nhận phần **vượt chuẩn** của nhân sự về **Skills** và **Traits** trong phạm vi role hiện tại, thay vì trả theo cảm tính hoặc chỉ theo thâm niên.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('d50eecc4-2a03-4707-a72f-e4ae7a117032','06-stars-luong-thuong','b0f4024b-a37c-469e-b78d-ed1fffdb8933',3,'Ý nghĩa của lương cứng theo vị trí','y-nghia-cua-luong-cung-theo-vi-tri',63,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('74d3e031-eddf-46b7-b268-74f4d483e131','d50eecc4-2a03-4707-a72f-e4ae7a117032',172,'text','Mỗi vị trí trong phòng khám phải có một **mức lương cứng chuẩn** tương ứng với vai trò nền của vị trí đó.
Mức lương cứng này phản ánh tối thiểu bốn yếu tố:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b40bc3f9-033a-463a-9370-d6795835cab4','d50eecc4-2a03-4707-a72f-e4ae7a117032',173,'text','- Số giờ làm việc hoặc cường độ hiện diện theo thỏa thuận.- Trách nhiệm cơ bản phải gánh.- Chuẩn năng lực tối thiểu để làm đúng vai trò.- Chuẩn hành vi tối thiểu để vận hành ổn định trong hệ thống.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('66e431de-66c2-4691-9501-b3be47a662dd','d50eecc4-2a03-4707-a72f-e4ae7a117032',174,'text','Ví dụ, ở vị trí **Bác sĩ**, lương cứng 15.000.000 đồng có thể được hiểu là mức trả cho:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('479a3090-7f48-42a6-bcb4-7943318d2005','d50eecc4-2a03-4707-a72f-e4ae7a117032',175,'text','- Có chứng chỉ hành nghề hợp lệ.- Đảm nhận đủ số giờ làm việc chuẩn của role.- Có kỹ năng cơ bản để điều trị đúng chuẩn ở phạm vi công việc đã giao.- Có mức kinh nghiệm, hồ sơ nghề nghiệp và độ tin cậy nghề nghiệp tối thiểu để giữ vị trí.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e03d46b7-c178-45d0-b8cb-e7bad1c26365','06-stars-luong-thuong','b0f4024b-a37c-469e-b78d-ed1fffdb8933',3,'Nguyên tắc chấm chuẩn role','nguyen-tac-cham-chuan-role',64,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a5f0d3a3-07ef-43f4-a3b9-6e9807295cf6','e03d46b7-c178-45d0-b8cb-e7bad1c26365',176,'text','Mỗi vị trí phải có một **Role Card S/T** riêng, trong đó xác định rõ:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2eeb4ff8-1084-4026-9b06-2d40fcd9dda6','e03d46b7-c178-45d0-b8cb-e7bad1c26365',177,'text','- Vị trí này cần những **Skills** nào.- Vị trí này cần những **Traits** nào.- Mức nào là **chuẩn tối thiểu để giữ role**.- Mức nào là **vượt chuẩn để được hưởng phụ cấp S.T**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d647797f-5ca9-4c58-ab32-6ab2d1c313e5','e03d46b7-c178-45d0-b8cb-e7bad1c26365',178,'text','Để vận hành đơn giản, role nên được chấm trên **thang chuẩn 10 điểm**, trong đó:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5dd1c1e7-4349-45c7-8336-f5e76ca3fd8f','e03d46b7-c178-45d0-b8cb-e7bad1c26365',179,'text','- **10 điểm** là mức đạt chuẩn nền của role, tương ứng với mức lương cứng hiện tại.- Điểm **vượt trên chuẩn** không làm thay đổi lương cứng ngay, mà được dùng để tính **phụ cấp S.T**.- Khi tổng mức vượt chuẩn đạt đến ngưỡng nâng bậc và có thêm trách nhiệm mới, nhân sự mới được xét tăng **lương cứng.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('502edb05-571d-4050-9543-eac5e53a2d15','06-stars-luong-thuong','b0f4024b-a37c-469e-b78d-ed1fffdb8933',3,'Cấu trúc Skills và Traits theo role','cau-truc-skills-va-traits-theo-role',65,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6d4c7a55-fd34-4b1e-a9ef-06708606f85a','502edb05-571d-4050-9543-eac5e53a2d15',180,'text','**Skills** là phần phản ánh năng lực chuyên môn để thực hiện công việc đúng chuẩn, bao gồm tay nghề, kỹ thuật, độ chính xác, tuân thủ quy trình, bằng cấp, chứng chỉ, kinh nghiệm và mức độ xử lý công việc độc lập.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('948b887d-6191-4221-b9e1-a2697570f438','502edb05-571d-4050-9543-eac5e53a2d15',181,'text','**Traits** là phần phản ánh nền phẩm chất nghề nghiệp, bao gồm kỷ luật, trách nhiệm, cẩn trọng, ổn định, chủ động, giữ lời, học hỏi và khả năng tự quản trong công việc hằng ngày.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c90e1b39-d07b-4596-af2a-c14d0d10100f','502edb05-571d-4050-9543-eac5e53a2d15',182,'text','Ví dụ với vị trí **Bác sĩ**, Skills có thể gồm:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d0d96b56-349b-4b21-adac-6c6268dfebc6','502edb05-571d-4050-9543-eac5e53a2d15',183,'text','- Chứng chỉ hành nghề.- Kỹ năng khám và chẩn đoán cơ bản.- Kỹ năng điều trị theo danh mục được giao.- Tuân thủ hồ sơ bệnh án và quy trình an toàn.- Kinh nghiệm xử lý ca.- Khả năng giao tiếp chuyên môn với bệnh nhân.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5ed1236d-4130-47b3-b44f-c5900abfdc8b','502edb05-571d-4050-9543-eac5e53a2d15',184,'text','Traits có thể gồm:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('48dcbce5-32f7-47a8-b1f3-81e401ce99bc','502edb05-571d-4050-9543-eac5e53a2d15',185,'text','- Đúng giờ và giữ cam kết điều trị.- Cẩn trọng và không bỏ sót bước.- Bình tĩnh, ổn định trong xử lý tình huống.- Chủ động phối hợp với phụ tá, lễ tân, CSKH.- Giữ chuẩn chính trực nghề nghiệp và không chạy số lệch chuẩn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('dad7fea3-5aff-4e3f-8835-46cb39c6b21d','06-stars-luong-thuong','b0f4024b-a37c-469e-b78d-ed1fffdb8933',3,'Tỷ trọng S/T theo vị trí','ty-trong-st-theo-vi-tri',66,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('aaeeb3ec-64c6-4162-9a65-c665d194ab2e','dad7fea3-5aff-4e3f-8835-46cb39c6b21d',186,'text','Không phải vị trí nào cũng có tỷ trọng Skills và Traits giống nhau; mỗi role cần một **tỷ trọng S/T riêng** tùy theo bản chất công việc.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d3e75a83-2490-4450-8d6e-0b633ae40198','dad7fea3-5aff-4e3f-8835-46cb39c6b21d',187,'text','Với những vị trí thiên về chuyên môn kỹ thuật như **Bác sĩ**, tỷ trọng nên nghiêng về Skills nhiều hơn, ví dụ **70% cho S và 30% cho T**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d4da8409-a755-4300-be8a-26f07e4bbff8','dad7fea3-5aff-4e3f-8835-46cb39c6b21d',188,'text','Với những vị trí thiên về ổn định vận hành, giao tiếp và phối hợp như lễ tân hoặc CSKH, tỷ trọng có thể cân bằng hơn hoặc nghiêng nhiều hơn về Traits.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('07ce3fed-3a95-4b2f-86d2-4c92d9c9ec49','dad7fea3-5aff-4e3f-8835-46cb39c6b21d',189,'text','Khung gợi ý:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a7dd4b4c-dac6-4731-8e0c-b92a75fa395c','dad7fea3-5aff-4e3f-8835-46cb39c6b21d',190,'text','- Bác sĩ: 70/30.- Phụ tá: 60/40.- Lễ tân/CSKH: 40/60 hoặc 50/50.- Vận hành/Finance: 50/50.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3d3a47d9-c9d1-40d8-9176-cb3b59a9899f','06-stars-luong-thuong','b0f4024b-a37c-469e-b78d-ed1fffdb8933',3,'Công thức tính phụ cấp S.T','cong-thuc-tinh-phu-cap-st',67,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('83009d6c-15ff-4fe8-a697-c2ecbaf8c2a5','3d3a47d9-c9d1-40d8-9176-cb3b59a9899f',191,'text','Phụ cấp S.T được tính trên **nền lương cứng của vị trí**, theo phần vượt chuẩn của Skills và Traits.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('08750326-296d-4dfd-b7a6-930dec096ed0','3d3a47d9-c9d1-40d8-9176-cb3b59a9899f',192,'text','Công thức đề xuất:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b91d8b1f-b9d1-4b5b-9d87-888d1715f9b8','3d3a47d9-c9d1-40d8-9176-cb3b59a9899f',193,'text','**Phụ cấp S = Lương cứng × Tỷ trọng S × Mức vượt chuẩn S**
**Phụ cấp T = Lương cứng × Tỷ trọng T × Mức vượt chuẩn T**
**Tổng phụ cấp S.T = Phụ cấp S + Phụ cấp T**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fc960007-6ec6-4b22-bee6-f8167cf5ddbb','3d3a47d9-c9d1-40d8-9176-cb3b59a9899f',194,'text','Trong đó:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('47b16d7a-db48-498e-805e-5a710d33b49f','3d3a47d9-c9d1-40d8-9176-cb3b59a9899f',195,'text','- **Tỷ trọng S** và **Tỷ trọng T** được xác định theo từng role.- **Mức vượt chuẩn S/T** là phần vượt thêm so với mức nền của role, tính theo tỷ lệ phần trăm hoặc hệ số chuẩn hóa nội bộ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b7081ea8-bbf5-45b5-af37-b8261d2e3437','06-stars-luong-thuong','b0f4024b-a37c-469e-b78d-ed1fffdb8933',3,'Ví dụ áp dụng cho vị trí Bác sĩ','vi-du-ap-dung-cho-vi-tri-bac-si',68,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('269d5782-302c-4adb-a0ed-52ebc7e2d790','b7081ea8-bbf5-45b5-af37-b8261d2e3437',196,'text','Giả sử: Bác Sĩ Nguyễn Phước Vinh, ứng viên bác sĩ Tổng Quát',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cbcd0627-9a26-4f96-8495-4ddf6ae2422a','b7081ea8-bbf5-45b5-af37-b8261d2e3437',197,'text','- Lương cứng của bác sĩ: **15.000.000 đồng**.- Tỷ trọng **S/T = 70/30**.- Mức vượt chuẩn **S = 0,2**.- Mức vượt chuẩn **T = 0,1**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0aace1db-841d-407c-83ef-674e48aaf826','b7081ea8-bbf5-45b5-af37-b8261d2e3437',198,'text','Khi đó:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('eadf365a-8af8-4b72-a648-d5a6e300b68f','b7081ea8-bbf5-45b5-af37-b8261d2e3437',199,'text','- Nền tính **S** = 15.000.000 × 70% = **10.500.000 đồng**.- Nền tính **T** = 15.000.000 × 30% = **4.500.000 đồng**.- Phụ cấp **S** = 10.500.000 × 20% = **2.100.000 đồng**.- Phụ cấp **T** = 4.500.000 × 10% = **450.000 đồng**.- Tổng phụ cấp **S.T** = **2.550.000 đồng**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c3f7e72f-f69e-45e3-b2b5-36abf2f5ce7f','b7081ea8-bbf5-45b5-af37-b8261d2e3437',200,'text','Tổng thu nhập phần nền và S.T trong ví dụ này là:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('eef2e8a8-6eb9-4962-a893-daff09d29b5a','b7081ea8-bbf5-45b5-af37-b8261d2e3437',201,'text','- **15.000.000 + 2.550.000 = 17.550.000 đồng**, chưa bao gồm thưởng A.R và thưởng Hiệp lực nếu có',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('d2bf7ab9-2899-4388-ab85-43bf081a273a','06-stars-luong-thuong','b0f4024b-a37c-469e-b78d-ed1fffdb8933',3,'Điều kiện tăng lương cứng','ieu-kien-tang-luong-cung',69,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9f3c82f9-4054-46ed-84ca-8c0752976d65','d2bf7ab9-2899-4388-ab85-43bf081a273a',202,'text','Phụ cấp S.T và tăng lương cứng là **hai cơ chế khác nhau**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4d4a9f82-84ae-43f8-99bb-cceb1cc4994f','d2bf7ab9-2899-4388-ab85-43bf081a273a',203,'text','Nhân sự **không được tăng lương cứng** chỉ vì có điểm S/T cao hơn chuẩn trong khi vẫn giữ nguyên phạm vi vai trò hiện tại.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b94374e3-906a-4910-a601-b62e2fbd531d','d2bf7ab9-2899-4388-ab85-43bf081a273a',204,'text','Lương cứng chỉ được điều chỉnh khi đồng thời thỏa mãn hai điều kiện:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9438458c-ed62-476f-916c-83e90647930d','d2bf7ab9-2899-4388-ab85-43bf081a273a',205,'text','- Nhân sự đạt **ngưỡng S+T mới** theo khung phân cấp của vị trí.- Nhân sự được giao **vai trò mới**, **mức trách nhiệm mới** hoặc **phạm vi công việc cao hơn**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('24e213bf-36fe-43ee-adb5-30dc913c60d0','d2bf7ab9-2899-4388-ab85-43bf081a273a',206,'text','Nếu một người đã đủ chuẩn năng lực cao hơn nhưng chưa thực sự đảm nhận role cao hơn, tổ chức chỉ ghi nhận bằng **phụ cấp S.T**, chưa điều chỉnh lương cứng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f47b1b79-ee42-4edc-8307-76b2d1891f53','06-stars-luong-thuong','b0f4024b-a37c-469e-b78d-ed1fffdb8933',3,'Thang phân cấp nhân sự theo vị trí','thang-phan-cap-nhan-su-theo-vi-tri',70,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3c46885d-acde-4758-8fd1-605e6412edab','f47b1b79-ee42-4edc-8307-76b2d1891f53',207,'text','Mỗi vị trí nên có tối thiểu **4–5 bậc phát triển**, ví dụ:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('88a85abd-542e-424f-bbb1-dfb894e86bd2','f47b1b79-ee42-4edc-8307-76b2d1891f53',208,'text','- Bậc 1: Đạt chuẩn tối thiểu để giữ role.- Bậc 2: Làm ổn định, ít lỗi, cần ít nhắc.- Bậc 3: Vượt chuẩn, có thể xử lý độc lập.- Bậc 4: Có thể hỗ trợ, hướng dẫn hoặc đỡ việc cho người khác.- Bậc 5: Sẵn sàng nhận vai trò lớn hơn hoặc phụ trách phạm vi cao hơn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bd4aac45-2d51-4332-a841-8661cd1f4694','f47b1b79-ee42-4edc-8307-76b2d1891f53',209,'text','Thang này giúp tổ chức tách rõ ba việc:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2931ae45-8a8a-4e6d-a6b0-fca44bf61797','f47b1b79-ee42-4edc-8307-76b2d1891f53',210,'text','- Ai đang **đạt chuẩn role**.- Ai đang **vượt chuẩn role**.- Ai đã **đủ điều kiện cho role cao hơn**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('dc8b613b-897c-4b38-9669-b3b8723e87d0','06-stars-luong-thuong','b0f4024b-a37c-469e-b78d-ed1fffdb8933',3,'Ngưỡng tối đa của phụ cấp S.T','nguong-toi-a-cua-phu-cap-st',71,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0958959a-1398-483b-920d-34dcb6affcd5','dc8b613b-897c-4b38-9669-b3b8723e87d0',211,'text','Để tránh phụ cấp S.T phình quá mức và làm méo cấu trúc lương, mỗi role cần có **trần phụ cấp S.T**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b1032f65-366b-4672-9131-e7f7903e8ff4','dc8b613b-897c-4b38-9669-b3b8723e87d0',212,'text','Khung gợi ý:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('dc596931-8bfe-471c-979e-549e04761ae3','dc8b613b-897c-4b38-9669-b3b8723e87d0',213,'text','- Với phần lớn vị trí: **tối đa 10%–30% lương cứng**.- Với vị trí chuyên môn cao như bác sĩ: có thể mở rộng đến **30%–40% lương cứng** nếu thị trường, hiệu quả vận hành và ngân sách cho phép.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4001b96e-1e7c-4208-b0f2-6758779d9849','dc8b613b-897c-4b38-9669-b3b8723e87d0',214,'text','Khi một nhân sự thường xuyên chạm trần phụ cấp S.T, tổ chức không nên tiếp tục cộng thêm vô hạn, mà phải xem xét:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('95c9a79f-4643-4e71-8651-10e1e7204b8a','dc8b613b-897c-4b38-9669-b3b8723e87d0',215,'text','- Tạo **bậc role mới**.- Mở **phạm vi trách nhiệm mới**.- Hoặc nâng **lương cứng** gắn với role cao hơn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('4d3259e1-8e53-40f8-8af8-daf93727cdbd','06-stars-luong-thuong','b0f4024b-a37c-469e-b78d-ed1fffdb8933',3,'Nguyên tắc công bằng và kiểm soát méo hành vi','nguyen-tac-cong-bang-va-kiem-soat-meo-hanh-vi',72,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('464bf14b-2bd7-43c9-be1a-8975a440c906','4d3259e1-8e53-40f8-8af8-daf93727cdbd',216,'text','Cơ chế này được thiết kế để tránh hai thái cực:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b3697958-2375-4438-9aff-052c2c4a5842','4d3259e1-8e53-40f8-8af8-daf93727cdbd',217,'text','- Chỉ trả lương theo thâm niên.- Chỉ trả thưởng theo doanh thu hoặc kết quả ngắn hạn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('03a5646e-49d6-40a1-80b3-e9b4dec756e4','4d3259e1-8e53-40f8-8af8-daf93727cdbd',218,'text','Trong môi trường y tế, mọi phụ cấp và thưởng đều phải nằm trong giới hạn của ONE LIGHT, nghĩa là:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7bbe0501-8e83-459b-8f46-6a3d90bb32ab','4d3259e1-8e53-40f8-8af8-daf93727cdbd',219,'text','- Không dùng kỹ năng để hợp thức hóa hành vi sai chuẩn.- Không dùng kết quả để bù cho vi phạm đạo đức hoặc quy trình.- Không nâng lương cứng nếu tổ chức chưa giao thêm vai trò thật.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('bf63e45e-ec95-4483-b509-58710681872e','06-stars-luong-thuong','b0f4024b-a37c-469e-b78d-ed1fffdb8933',3,'Điều khoản chốt','ieu-khoan-chot',73,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6610bd82-1309-4c6a-be00-65c57e47a350','bf63e45e-ec95-4483-b509-58710681872e',220,'text','Lương cứng trả cho nền vai trò; phụ cấp S.T trả cho mức vượt chuẩn về Skills và Traits trong phạm vi role hiện tại; tăng lương cứng chỉ áp dụng khi nhân sự đạt ngưỡng S+T mới và được giao vai trò hoặc trách nhiệm cao hơn. Mỗi vị trí phải có Role Card riêng, tỷ trọng S/T riêng, thang phân cấp riêng và trần phụ cấp S.T rõ ràng để bảo đảm công bằng, minh bạch và kiểm soát chi phí nhân sự.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f8f874f5-a086-4023-bed6-aa56525148d8','06-stars-luong-thuong','2b91b460-892a-4138-b284-483177963567',2,'Thưởng A.R','thuong-ar',74,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cf3e4f80-ddf2-4c5f-90b8-02527db5a781','f8f874f5-a086-4023-bed6-aa56525148d8',221,'text','Thưởng A.R là phần thưởng cá nhân theo vai trò, được chi trả cho hành động thực thi đúng và kết quả đo lường được mà nhân sự tạo ra trong kỳ.
**Thưởng A.R = Thưởng hành động đúng +  Thưởng hiệu quả tốt + Thưởng cải tiến hệ thống**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('451165ed-f357-423f-91f6-26cdd90e2a8e','f8f874f5-a086-4023-bed6-aa56525148d8',222,'text','- Phần **A – Actions** ghi nhận việc nhân sự có làm đều, làm đủ, làm đúng checklist, làm đúng quy trình và không bỏ sót các điểm quan trọng trong công việc hằng ngày hay không.- Phần **R – Results** ghi nhận kết quả rõ ràng, đo được, phù hợp mục tiêu role và không tạo ra bằng cách vi phạm ONE LIGHT.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f72ae8ea-b712-4b6d-875b-f651c76372b2','f8f874f5-a086-4023-bed6-aa56525148d8',223,'text','Thưởng A.R chỉ được áp dụng khi có tiêu chí rõ, số liệu đo được, nguồn dữ liệu tin cậy và mối liên hệ trực tiếp với mục tiêu tháng hoặc quý.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('904ae592-c154-4c08-9cd5-3de6728ee4fd','f8f874f5-a086-4023-bed6-aa56525148d8',224,'text','Phòng khám không thưởng A.R cho các kết quả đẹp về bề ngoài nhưng chất lượng thấp, dữ liệu không sạch, gây tổn hại trải nghiệm khách hàng hoặc làm méo hành vi hệ thống.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f2fca059-53cc-4dc9-a8bd-4c8e936ae049','06-stars-luong-thuong','f8f874f5-a086-4023-bed6-aa56525148d8',3,'7.1 Cấu trúc chi tiết của A.R','71-cau-truc-chi-tiet-cua-ar',75,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c57655b5-06e5-4382-affb-8be547b12bfd','f2fca059-53cc-4dc9-a8bd-4c8e936ae049',225,'text','A.R được chia thành bốn nhóm thành phần để dễ áp dụng thực tế.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d036670a-e34d-46e2-b738-63482899d254','f2fca059-53cc-4dc9-a8bd-4c8e936ae049',226,'text','- **Thưởng hành động đúng**
Đây là phần thưởng dành cho việc thực thi đúng checklist, đúng nhịp, đúng quy trình và đúng vai trò.
Ví dụ: cập nhật CRM đầy đủ, phản hồi khách đúng thời gian, chuẩn bị ca đúng chuẩn, bàn giao đủ thông tin, hoàn tất hồ sơ đúng hạn hoặc thực hiện đủ các bước follow-up theo yêu cầu role.- ** Thưởng hiệu quả tốt**
Đây là phần thưởng dành cho việc tạo ra kết quả với chất lượng, hiệu suất hoặc độ bền tốt hơn, chứ không chỉ “đạt số”.
Ví dụ: ít lỗi hơn, ít hủy lịch hơn, tỷ lệ hài lòng cao hơn, ít tái xử lý hơn, hiệu suất ghế tốt hơn, chất lượng tư vấn tốt hơn hoặc hiệu quả marketing tốt hơn trên cùng một mức chi phí.- ** Thưởng cải tiến hệ thống**
Đây là phần thưởng cho các sáng kiến hoặc điều chỉnh tạo ra cách làm tốt hơn cho role, circle hoặc toàn phòng khám.
Một cải tiến chỉ được tính thưởng khi được áp dụng thực tế, có tác động đo được như giảm lỗi, tăng tốc độ vận hành, tăng độ chuẩn hóa, tăng trải nghiệm khách hàng hoặc giúp các bộ phận khác phối hợp hiệu quả hơn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f4f36f66-d876-451c-939a-73870e319fdd','06-stars-luong-thuong','f8f874f5-a086-4023-bed6-aa56525148d8',3,'7.2 A.R theo từng nhóm vai trò','72-ar-theo-tung-nhom-vai-tro',76,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('559c49fb-d10e-4c6d-8f0c-29c2312db4f2','f4f36f66-d876-451c-939a-73870e319fdd',227,'text','Mỗi role được áp dụng A.R theo chỉ số riêng, không áp dụng đồng loạt một công thức cho tất cả.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f07bf260-32aa-48b6-ad21-afbb949ff7e2','f4f36f66-d876-451c-939a-73870e319fdd',228,'text','- Với **bác sĩ**, A.R có thể gồm: mức hoàn tất điều trị theo phác đồ, chất lượng hồ sơ bệnh án, doanh thu/case hợp lệ, mức hài lòng sau điều trị, giảm lỗi lâm sàng và các cải tiến chuyên môn hoặc quy trình điều trị.- Với **phụ tá**, A.R có thể gồm: mức sẵn sàng ca, chuẩn vô khuẩn, giảm lỗi chuẩn bị, hiệu suất hỗ trợ ghế, bàn giao đầy đủ và các cải tiến trong set-up, checklist hoặc luồng ca điều trị.- Với **sales/tư vấn**, A.R có thể gồm: tỷ lệ booking, tỷ lệ show-up, tỷ lệ chốt, doanh thu, chất lượng follow-up và chất lượng quản trị pipeline khách hàng.- Với **CSKH/lễ tân**, A.R có thể gồm: thời gian phản hồi, tỷ lệ nhắc lịch đúng, tỷ lệ tái khám, tỷ lệ giữ chân khách, số review thật, số referral và độ sạch dữ liệu CRM.- Với **marketing**, A.R có thể gồm: số lead chất lượng, số booking từ marketing, CAC, ROI, số content đúng chuẩn, mức tăng trưởng kênh và chất lượng tracking/báo cáo.- Với **finance/data/system**, A.R có thể gắn với độ chính xác dữ liệu, đúng hạn báo cáo, độ sạch dashboard, tốc độ xử lý số liệu và mức độ hỗ trợ ra quyết định cho founder và các circle khác.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5f24af94-0646-446e-a9fd-9c15c743ea59','06-stars-luong-thuong','f8f874f5-a086-4023-bed6-aa56525148d8',3,'7.3 Các trường hợp không được thưởng A.R','73-cac-truong-hop-khong-uoc-thuong-ar',77,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5b210103-35b3-4f0d-bd1f-c0f8ea94a2d3','5f24af94-0646-446e-a9fd-9c15c743ea59',229,'text','Không thưởng A.R cho bất kỳ kết quả nào đạt được bằng cách tư vấn sai sự thật, làm dư, ép khách, xin review sai thời điểm, phóng đại truyền thông, sửa số liệu tùy tiện hoặc bỏ qua quy trình an toàn và chuẩn nghề nghiệp.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('28e3688b-1b79-4b86-926a-eab22b10f657','5f24af94-0646-446e-a9fd-9c15c743ea59',230,'text','Không thưởng booking nếu tư vấn sai sự thật, không thưởng review nếu ép khách, không thưởng doanh thu nếu bác sĩ làm dư hoặc tư vấn quá mức, và không thưởng lead nếu lead không chất lượng và không chuyển đổi.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('92d9c6fc-577b-4242-a1f1-fde474488e0b','5f24af94-0646-446e-a9fd-9c15c743ea59',231,'text','Ngoài các trường hợp trên, phòng khám có quyền tạm dừng hoặc giảm A.R nếu dữ liệu không đầy đủ, KPI không được cập nhật đúng quy trình, có tranh chấp về tính chính xác của số liệu hoặc có vi phạm nghiêm trọng ảnh hưởng đến khách hàng, đội ngũ hay thương hiệu phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('53d9b282-b7ec-45fe-b4c7-a7f902740e6d','5f24af94-0646-446e-a9fd-9c15c743ea59',232,'text','Mọi khoản A.R đều phải có khả năng giải trình bằng số liệu, biên bản, dashboard hoặc dấu vết công việc tương ứng',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('26ac513f-55aa-4ac5-9f17-24324efcceb7','06-stars-luong-thuong','2b91b460-892a-4138-b284-483177963567',2,'Công thức thưởng Synergy cá nhân','cong-thuc-thuong-synergy-ca-nhan',78,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8419bd5c-a8b0-499b-b4ff-7d68c96e913c','26ac513f-55aa-4ac5-9f17-24324efcceb7',233,'image',NULL,'book/06-stars-luong-thuong/6b3d6f91-7125-45d3-a10c-fd711a9f1b3c-img14.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e7ef482e-d430-447b-9bf8-206a72ef27e1','06-stars-luong-thuong','26ac513f-55aa-4ac5-9f17-24324efcceb7',3,'8.1 Thưởng Hiệp Lực (Synergy) là gì?','81-thuong-hiep-luc-synergy-la-gi',79,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('dc84b497-aa2a-4049-997d-c1b82accaf39','e7ef482e-d430-447b-9bf8-206a72ef27e1',234,'text','- Synergy là khoản thưởng nhằm ghi nhận đóng góp thực tế của cá nhân vào kết quả chung của Circle, đồng thời khuyến khích hành vi đúng chuẩn, tinh thần hợp tác và hiệu suất bền vững.- Synergy không chỉ trả cho kết quả đầu ra, mà còn trả cho chất lượng thực thi và chất lượng hành vi trong quá trình tạo ra kết quả đó.- Áp dụng cho tất cả các nhân sự trong tổ chức. Mỗi Phòng ban (Circle) được cấp 1 quỹ thưởng tùy tỉ trọng mà tổ chức thống nhất. Mỗi cá nhân trong Circle đó được chia theo tỉ trọng mà Circle đó quy định.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('74c2114f-95a3-438e-a72c-e48b4b268e68','06-stars-luong-thuong','26ac513f-55aa-4ac5-9f17-24324efcceb7',3,'8.2 Công thức','82-cong-thuc',80,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0c396d6f-30e5-41af-97f2-aad7e8c166f3','74c2114f-95a3-438e-a72c-e48b4b268e68',235,'text','- **Thưởng Synergy cá nhân = (Quỹ Circle × Hệ số ONE LIGHT Circle) × (Tỷ trọng cá nhân × Hệ số S.T.A.R.S cá nhân) **.
Trong đó, **S.T.A.R.S** phản ánh năng lực, hành động, kết quả và hiệp lực; còn **ONE LIGHT** phản ánh chất lượng hành vi và mức độ chính trực',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1337f88c-e4c0-4060-827e-1ad13c96c653','06-stars-luong-thuong','26ac513f-55aa-4ac5-9f17-24324efcceb7',3,'8.3 Cách chấm hệ số','83-cach-cham-he-so',81,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a1130f44-0a89-48e9-b22e-f38086576f5a','1337f88c-e4c0-4060-827e-1ad13c96c653',236,'text','- Hệ số **S.T.A.R.S** và **ONE LIGHT** được chấm theo thang nội bộ, sau đó **chuẩn hóa trong khung trần đã công bố trước** để không làm tổng chi vượt quỹ.- Để vận hành ổn định, mỗi hệ số nên có biên độ rõ ràng, ví dụ từ 0.8 đến 1.1 hoặc theo mức mà policy phê duyệt, và không được vượt trần đã khóa.- Việc chấm phải dựa trên checklist, KPI, quan sát thực tế và phản hồi phối hợp, không dựa vào cảm tính.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('357806e0-703e-457d-8609-fcbd26d31e84','06-stars-luong-thuong','26ac513f-55aa-4ac5-9f17-24324efcceb7',3,'8.4 Ai chấm','84-ai-cham',82,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('030ea267-883c-4e6b-9314-4a94b32fda34','357806e0-703e-457d-8609-fcbd26d31e84',237,'text','- Quản lý trực tiếp là người chấm chính vì họ quan sát được hành vi hằng ngày, còn Circle lead hoặc HR duyệt lại các trường hợp nhạy cảm, chênh lệch lớn hoặc có tranh chấp.- Như vậy, điểm số vừa phản ánh thực tế vận hành vừa có lớp kiểm soát để bảo đảm công bằng và thống nhất.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ef21b012-82c8-49fe-87ae-ddb7f06f9015','06-stars-luong-thuong','26ac513f-55aa-4ac5-9f17-24324efcceb7',3,'8.5 Quỹ có thể dư hay thiếu','85-quy-co-the-du-hay-thieu',83,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('08bd86cc-ee0a-4984-ba99-4fb105426fe5','ef21b012-82c8-49fe-87ae-ddb7f06f9015',238,'text','- Nếu chỉ nhân hệ số mà không khóa trần, tổng thưởng có thể vượt quỹ hoặc còn dư quỹ.- Vì vậy, policy phải quy định rõ: **tổng tỷ trọng cá nhân trong Circle bằng 100%**, hệ số được **chuẩn hóa theo trần**, và **tổng payout không được vượt Quỹ Circle đã chốt**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('d3eaa4aa-6360-4f72-be28-b4d2e4083998','06-stars-luong-thuong','26ac513f-55aa-4ac5-9f17-24324efcceb7',3,'8.6 Xử lý quỹ dư','86-xu-ly-quy-du',84,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6baba19e-72d5-4113-b49f-b8c3daaab086','d3eaa4aa-6360-4f72-be28-b4d2e4083998',239,'text','- Nếu cuối kỳ còn dư quỹ, phần dư không chia tùy ý mà phải theo rule cố định đã công bố trước.- Cách hợp lý nhất là: **80–90% quỹ dư chuyển sang kỳ sau**, phần còn lại đưa vào **quỹ đào tạo, phúc lợi hoặc cải tiến tập thể** để giữ tinh thần hiệp lực và công bằng.- Cách này giúp nhân sự thấy rằng quỹ dư không bị “mất”, mà quay lại phục vụ chính người làm ra giá trị và hệ thống họ đang cùng xây.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f07ff210-196e-46cb-bb66-172d7f399867','06-stars-luong-thuong','26ac513f-55aa-4ac5-9f17-24324efcceb7',3,'8.7 Nguyên tắc công bằng','87-nguyen-tac-cong-bang',85,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('af10bc54-94e6-426e-b934-28f1fc8aeadb','f07ff210-196e-46cb-bb66-172d7f399867',240,'text','- Synergy chỉ tạo cảm giác công bằng khi 4 điều được giữ ổn định: tiêu chí rõ, cách chấm rõ, trần quỹ rõ, và rule quỹ dư rõ.- Nếu mỗi kỳ thay cách tính hoặc xử lý quỹ dư khác nhau, người trong team sẽ cảm thấy thiếu minh bạch dù số tiền có thể vẫn nhiều.- Ngược lại, khi rule cố định và số liệu minh bạch, người ít được thưởng vẫn dễ chấp nhận hơn vì họ hiểu đây là hệ thống công bằng chứ không phải quyết định cảm tính.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('27e1beca-b966-4b86-9d1c-2324a62ec12f','06-stars-luong-thuong','26ac513f-55aa-4ac5-9f17-24324efcceb7',3,'8.8 Policy gợi ý','88-policy-goi-y',86,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9ceb3f81-9d5b-42c0-a9ae-20aa53d2a1d8','27e1beca-b966-4b86-9d1c-2324a62ec12f',241,'text','- Synergy là khoản thưởng biến động theo kết quả Circle, được tính bằng Quỹ Circle × Tỷ trọng cá nhân × Hệ số S.T.A.R.S chuẩn hóa × Hệ số ONE LIGHT chuẩn hóa. - Tỷ trọng cá nhân phải cộng đủ 100% trong Circle, hệ số phải nằm trong trần đã công bố, và tổng thưởng không được vượt Quỹ Circle đã chốt. - Nếu còn dư quỹ, phần dư được xử lý theo rule cố định, ưu tiên chuyển kỳ sau và/hoặc bổ sung quỹ phát triển tập thể.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7d36c409-88bf-4289-86f2-ca1d729fdfb8','06-stars-luong-thuong','26ac513f-55aa-4ac5-9f17-24324efcceb7',3,'8.9 Ví dụ ngắn','89-vi-du-ngan',87,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a1a64cbc-235e-4760-a977-636e5b6f7946','7d36c409-88bf-4289-86f2-ca1d729fdfb8',242,'text','Giả sử:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a5bc789e-c7cf-4556-a906-4a13632d0de0','7d36c409-88bf-4289-86f2-ca1d729fdfb8',243,'text','- Quỹ thưởng gốc của Circle là **100.000.000đ**.- **ONE LIGHT Circle = 0,90**.- Vậy **quỹ mở = 100.000.000 × 0,90 = 90.000.000đ**.- Tổng tỷ trọng cá nhân trong Circle là 100%.- Một nhân sự A có **tỷ trọng 20%** và **hệ số S.T.A.R.S = 1,0**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e09b1281-5200-455e-ab0b-442b3429b39c','7d36c409-88bf-4289-86f2-ca1d729fdfb8',244,'text','Khi đó, **Synergy cá nhân của A = 90.000.000 × 20% × 1,0 = 18.000.000đ**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ff7a3062-d5de-478f-9918-ccb3bce9b8d6','7d36c409-88bf-4289-86f2-ca1d729fdfb8',245,'text','Ví dụ có chênh lệch S.T.A.R.S',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('aa6e4b26-6758-4344-b491-ad250a05672f','7d36c409-88bf-4289-86f2-ca1d729fdfb8',246,'text','Giả sử cùng quỹ mở là **90.000.000đ**:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bc0f01b0-14a7-4198-abef-a71e81779526','7d36c409-88bf-4289-86f2-ca1d729fdfb8',247,'text','- Nhân sự A: tỷ trọng 20%, S.T.A.R.S 1,0.- Nhân sự B: tỷ trọng 20%, S.T.A.R.S 0,8.- Nhân sự C: tỷ trọng 20%, S.T.A.R.S 1,2.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('509e4499-5151-4e54-9c73-d972d48e7d0e','7d36c409-88bf-4289-86f2-ca1d729fdfb8',248,'text','Thì:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('51796431-8d5b-4e40-8aa0-8a8eae73dcb0','7d36c409-88bf-4289-86f2-ca1d729fdfb8',249,'text','- A nhận **18.000.000đ**.- B nhận **14.400.000đ**.- C nhận **21.600.000đ**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('73c3628d-56ae-4095-bbeb-6588fd3d5650','7d36c409-88bf-4289-86f2-ca1d729fdfb8',250,'text','Cùng tỷ trọng, nhưng người có S.T.A.R.S cao hơn sẽ nhận Synergy cao hơn vì đóng góp hiệp lực tốt hơn cho Circle.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7a0df1bc-95b2-4589-914d-f579ed3a80b7','7d36c409-88bf-4289-86f2-ca1d729fdfb8',251,'text','Ví dụ ONE LIGHT thấp hơn',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('84311810-c724-4f86-9a25-72f3d8bdb895','7d36c409-88bf-4289-86f2-ca1d729fdfb8',252,'text','Nếu:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ad1b196f-6d64-44a9-92af-402ecfd91746','7d36c409-88bf-4289-86f2-ca1d729fdfb8',253,'text','- Quỹ thưởng gốc = **100.000.000đ**.- **ONE LIGHT Circle = 0,70**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b8f4a24f-4596-4799-9171-d21169bd58cb','7d36c409-88bf-4289-86f2-ca1d729fdfb8',254,'text','Thì:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3eb1e015-71b8-411c-ad22-acab4922508c','7d36c409-88bf-4289-86f2-ca1d729fdfb8',255,'text','- **Quỹ mở = 70.000.000đ**.- Phần **30.000.000đ** còn lại chưa được mở trong kỳ này.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7dddcd60-e098-4d00-ba38-737adb14fc9a','7d36c409-88bf-4289-86f2-ca1d729fdfb8',256,'text','Khi đó, Synergy cá nhân vẫn tính trên **70.000.000đ**, nên cả Circle sẽ thấy rõ rằng nếu mức tuân thủ tập thể thấp thì quỹ chung bị giảm, dù cá nhân làm tốt vẫn bị ảnh hưởng theo cơ chế vòng tròn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('45d71598-5a27-4de8-8e75-b4302f55daf1','06-stars-luong-thuong','26ac513f-55aa-4ac5-9f17-24324efcceb7',3,'8.10 Ý nghĩa quản trị','810-y-nghia-quan-tri',88,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c9dd78a2-3089-44a9-a7d1-6950ccc32046','45d71598-5a27-4de8-8e75-b4302f55daf1',257,'text','Cách thưởng mới này có 3 tầng rõ ràng:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('083c9712-87cf-45ae-8466-0c5a5de1c3a8','45d71598-5a27-4de8-8e75-b4302f55daf1',258,'text','- **ONE LIGHT** quyết định Circle được mở bao nhiêu quỹ thưởng.- **Tỷ trọng cá nhân** quyết định người đó chiếm bao nhiêu phần trong quỹ mở.- **S.T.A.R.S** điều chỉnh phần hưởng theo mức đóng góp hiệp lực thực tế.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ed953905-ab30-4e24-b78c-2b1c8ac3724d','06-stars-luong-thuong','26ac513f-55aa-4ac5-9f17-24324efcceb7',3,'8.11 Chỉ số dùng cho Synergy','811-chi-so-dung-cho-synergy',89,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('50389ee0-8752-455b-98b6-664802ec8937','ed953905-ab30-4e24-b78c-2b1c8ac3724d',259,'text','Synergy có thể được tính theo một hoặc nhiều nhóm chỉ số chung sau đây: doanh thu toàn phòng khám, lợi nhuận, tỷ lệ khách quay lại, số review thật, số referral mới, điểm hài lòng khách hàng, tỷ lệ lỗi bàn giao thấp, mức phối hợp liên bộ phận và mức hoàn thành mục tiêu của circle.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ec3d4454-753b-4bcd-afbb-a91c2c7051ec','ed953905-ab30-4e24-b78c-2b1c8ac3724d',260,'text','Phòng khám có thể chọn bộ chỉ số Synergy phù hợp theo quy mô, nhưng các chỉ số này phải rõ, đo được và được công bố trước kỳ áp dụng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('80ca2f03-ff23-4dbc-8474-bdbe2f5e7dc5','ed953905-ab30-4e24-b78c-2b1c8ac3724d',261,'text','Một số chỉ số đặc biệt phù hợp cho Synergy là trải nghiệm khách hàng, review và referral vì đây là kết quả chung của marketing, sales, lễ tân, bác sĩ, phụ tá, CSKH và vận hành.
Không nên thưởng Synergy một cách máy móc nếu có thành viên vi phạm nghiêm trọng Integrity hoặc gây tổn hại đáng kể đến hiệu quả chung của cả đội.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('95c25153-1b38-4b8b-a9fb-5606bf629ba5','06-stars-luong-thuong','2b91b460-892a-4138-b284-483177963567',2,'Cơ chế giữ thưởng (Retention)','co-che-giu-thuong-retention',90,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('927ab78b-6eb5-4466-8369-21f5aee2eeb7','95c25153-1b38-4b8b-a9fb-5606bf629ba5',262,'image',NULL,'book/06-stars-luong-thuong/849aaf32-09c6-4c5e-9345-e9cd426a59be-img15.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('aa3fcfad-7958-422d-a7cb-679b5d097f0b','06-stars-luong-thuong','95c25153-1b38-4b8b-a9fb-5606bf629ba5',3,'9.1 Cấu trúc giữ thưởng','91-cau-truc-giu-thuong',91,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7e5c8813-8f74-4fce-92a1-e8bc729cf8a4','aa3fcfad-7958-422d-a7cb-679b5d097f0b',263,'text','- **70–80% trả ngay**: đây là phần thưởng đã xác nhận, được chi trả gần như ngay sau kỳ tính thưởng.- **20–30% giữ lại 2–3 tháng**: đây là phần thưởng treo lại để kiểm tra sự ổn định, tính cam kết và mức độ không phát sinh rủi ro hệ thống.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('eb4ba1a4-2683-4387-85b3-583a95ef3743','aa3fcfad-7958-422d-a7cb-679b5d097f0b',264,'text','Cách này giúp hệ thống vừa tạo động lực ngắn hạn, vừa giữ người và giữ chuẩn vận hành dài hơn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('8cb3dbfc-3eb7-46d0-9a6b-3cab5040f831','06-stars-luong-thuong','95c25153-1b38-4b8b-a9fb-5606bf629ba5',3,'9.2 Điều kiện nhận đủ','92-ieu-kien-nhan-u',92,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f546ef96-d790-48d3-91e0-69ee643718fc','8cb3dbfc-3eb7-46d0-9a6b-3cab5040f831',265,'text','Phần giữ lại chỉ được trả đủ khi đáp ứng đồng thời các điều kiện sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2f3a1941-4612-4720-93c3-5b6b0fe4ad83','8cb3dbfc-3eb7-46d0-9a6b-3cab5040f831',266,'text','- **Không vi phạm**.- **Không nghỉ việc**.- **Không gây lỗi hệ thống**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8f87d1ee-f509-46fb-a1d8-fe31a738b512','8cb3dbfc-3eb7-46d0-9a6b-3cab5040f831',267,'text','Hiểu đơn giản, retention không chỉ thưởng cho kết quả đã làm ra, mà còn thưởng cho **độ tin cậy sau khi nhận thưởng**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ec39e10d-cdaf-496c-ba1e-0563439c3751','06-stars-luong-thuong','95c25153-1b38-4b8b-a9fb-5606bf629ba5',3,'9.3 Ý nghĩa quản trị','93-y-nghia-quan-tri',93,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cd721e1a-afb7-4518-aa39-ac5c1bbedd02','ec39e10d-cdaf-496c-ba1e-0563439c3751',268,'text','Cơ chế này rất hữu ích khi phòng khám muốn tránh tình trạng nhân sự làm tốt trong ngắn hạn nhưng rời đi sớm, gây đứt gãy quy trình hoặc phát sinh lỗi sau đó.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d855ab9e-bf8b-4cb4-9c3e-9eb2bd48abd8','ec39e10d-cdaf-496c-ba1e-0563439c3751',269,'text','Nó cũng giúp giảm rủi ro “nhận thưởng xong rồi mất kiểm soát”, vì một phần tiền được giữ lại như lớp bảo vệ cho hệ thống',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3fe10728-05d5-4f76-9f94-b8209e1a49bb','06-stars-luong-thuong','95c25153-1b38-4b8b-a9fb-5606bf629ba5',3,'9.4 Điều kiện mở - khóa thưởng','94-ieu-kien-mo-khoa-thuong',94,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0e0ae205-a361-43a6-a043-44dc495a628f','3fe10728-05d5-4f76-9f94-b8209e1a49bb',270,'text','- **Khóa Synergy** khi doanh thu dưới hòa vốn vì hệ thống chưa tạo đủ nền để thưởng cho đóng góp tập thể.- **Giảm quỹ** khi chi phí vượt kiểm soát vì đây là dấu hiệu vận hành lệch chuẩn tài chính.- **Giữ thưởng** khi sai số liệu vì chưa đủ tin cậy để giải ngân đầy đủ, cần xác minh lại dữ liệu.- **Khóa Clinical** khi có lỗi chuyên môn vì chất lượng điều trị là điều kiện bắt buộc.- **Khóa Growth** khi có lead ảo vì tăng trưởng phải dựa trên tín hiệu thật.- **Khóa toàn hệ** khi gian lận vì đây là vi phạm cấp hệ thống, không chỉ là lỗi cá nhân.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('8524ec26-c667-4ab3-9d65-0df38b6ebff0','06-stars-luong-thuong','2b91b460-892a-4138-b284-483177963567',2,'Chu kỳ đánh giá và chi trả','chu-ky-anh-gia-va-chi-tra',95,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a6f80975-55cb-4bb5-873f-6b2bfa82f673','8524ec26-c667-4ab3-9d65-0df38b6ebff0',271,'text','Đánh giá hiệu suất có thể được thực hiện theo tuần, tháng hoặc quý tùy từng lớp chỉ số và từng role.
Các chỉ số vận hành ngắn hạn như checklist, phản hồi khách, booking, doanh thu, show-up hoặc lỗi vận hành nên được theo dõi hằng tuần hoặc hằng tháng; các chỉ số mang tính phát triển hơn như bậc năng lực S.T hoặc mức độ phù hợp vai trò có thể rà soát theo quý.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('da84b0cd-b4f0-40a1-842a-cfd3edb7cdc2','8524ec26-c667-4ab3-9d65-0df38b6ebff0',272,'text','Lương cứng được chi trả theo kỳ lương cố định của phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c4aa0354-2ddf-4c83-9d54-01d5274d66e3','8524ec26-c667-4ab3-9d65-0df38b6ebff0',273,'text','Phụ cấp S.T, A.R và Synergy có thể được tổng hợp theo tháng và điều chỉnh hoặc xác nhận theo chu kỳ review chính thức, miễn là nguyên tắc áp dụng được công bố rõ từ đầu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f4000867-15db-4473-b92f-d328536e2f9d','06-stars-luong-thuong','2b91b460-892a-4138-b284-483177963567',2,'Dữ liệu và trách nhiệm xác nhận','du-lieu-va-trach-nhiem-xac-nhan',96,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4de8cd57-c73f-42dc-9b10-bcf1912a8555','f4000867-15db-4473-b92f-d328536e2f9d',274,'text','- Tất cả các khoản thưởng phải dựa trên dữ liệu có nguồn gốc rõ ràng như CRM, dashboard, báo cáo tài chính, checklist, log công việc, báo cáo circle hoặc biên bản họp định kỳ.- Không sử dụng lời kể miệng, cảm nhận chủ quan hoặc đánh giá thiếu bằng chứng làm căn cứ duy nhất để xác lập thưởng.- Người quản lý role, circle lead hoặc người được ủy quyền có trách nhiệm xác nhận dữ liệu trước khi chuyển sang bước tổng hợp lương thưởng.- Bộ phận finance hoặc người phụ trách dữ liệu có trách nhiệm đối chiếu tính hợp lệ của các con số và lưu dấu vết kiểm tra để bảo đảm minh bạch nội bộ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('dc82b4ed-9559-47b4-a97d-fdc5e1c4d6b3','06-stars-luong-thuong','2b91b460-892a-4138-b284-483177963567',2,'Xử lý vi phạm và điều chỉnh','xu-ly-vi-pham-va-ieu-chinh',97,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4e20fa0e-cbc7-4d23-9a85-dbebe7e3c339','dc82b4ed-9559-47b4-a97d-fdc5e1c4d6b3',275,'text','- Phòng khám có quyền giảm, tạm dừng hoặc hủy một phần thưởng nếu phát hiện sai lệch dữ liệu, vi phạm quy trình, vi phạm an toàn, vi phạm Integrity hoặc hành vi gây tổn hại cho khách hàng và hệ thống.- Trường hợp vi phạm nghiêm trọng có thể đồng thời kéo theo điều chỉnh vai trò, cảnh báo, kế hoạch cải thiện hoặc xem xét lại mức độ phù hợp lâu dài với tổ chức.- Việc điều chỉnh thưởng phải được giải thích rõ bằng tiêu chí, dữ liệu hoặc biên bản liên quan, tránh xử lý cảm tính.
Nhân sự có quyền được biết lý do điều chỉnh và được phản hồi qua đúng kênh quản trị nội bộ của phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('44439398-82a5-424b-9317-720e3338067a','06-stars-luong-thuong','2b91b460-892a-4138-b284-483177963567',2,'Điều khoản áp dụng','ieu-khoan-ap-dung',98,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6cfe79e5-12cc-4c4f-9fe5-434d91cbfde2','44439398-82a5-424b-9317-720e3338067a',276,'text','- Chính sách này áp dụng cho toàn bộ nhân sự thuộc hệ thống phòng khám, bao gồm các nhóm role lâm sàng, vận hành, patient care, growth, finance và data, với mức độ chi tiết và KPI cụ thể được quy định tại từng Role Card hoặc phụ lục KPI đi kèm.- Trong trường hợp một nhân sự kiêm nhiều role, việc tính thu nhập và thưởng sẽ dựa trên tổng phạm vi trách nhiệm thực tế và bộ KPI tương ứng của từng role, tránh trả lương trùng lặp nhưng vẫn bảo đảm ghi nhận đúng phần đóng góp.- Mọi sửa đổi đối với chính sách này phải được ghi nhận thành policy chính thức, thông báo rõ ràng trước khi áp dụng và lưu trong hệ thống quản trị nội bộ.- Tinh thần xuyên suốt của chính sách là: **trả đúng cho nền trách nhiệm, ghi nhận đúng cho năng lực ổn định, thưởng đúng cho kết quả thật và khuyến khích đúng cho hiệp lực bền vững**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('80177ac7-7d80-412d-9679-d3b1bc5fdb82','06-stars-luong-thuong','2b91b460-892a-4138-b284-483177963567',2,'Mô hình thu nhập bác sĩ và phụ tá','mo-hinh-thu-nhap-bac-si-va-phu-ta',99,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('dc0f95e9-0163-4085-b35f-0ef092cb2361','06-stars-luong-thuong','80177ac7-7d80-412d-9679-d3b1bc5fdb82',3,'14.1 Bác sĩ','141-bac-si',100,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('933d1aac-664f-40fc-9b4d-bc153d5ba41d','06-stars-luong-thuong','dc0f95e9-0163-4085-b35f-0ef092cb2361',4,'Định nghĩa','inh-nghia',101,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('188dc4ea-65ea-4400-abc6-2abe3854694f','933d1aac-664f-40fc-9b4d-bc153d5ba41d',277,'text','Bác sĩ là vai trò chuyên môn cốt lõi trong Clinical Circle, chịu trách nhiệm chẩn đoán, lập phác đồ, điều trị, bàn giao sau điều trị và đóng góp vào kết quả chuyên môn, doanh thu, trải nghiệm và uy tín của phòng khám.
Bác sĩ full-time được đánh giá theo các chỉ số như consultation completion (tỷ lệ hoàn tất tư vấn), treatment acceptance rate (tỷ lệ chấp nhận điều trị), treatment completion rate (tỷ lệ hoàn tất điều trị), revenue per consultation (doanh thu trên mỗi buổi tư vấn), chất lượng hồ sơ, sự cố chuyên môn và số case chất lượng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('88a0c865-1202-45b2-9925-134c777f28ff','06-stars-luong-thuong','dc0f95e9-0163-4085-b35f-0ef092cb2361',4,'Công thức thu nhập','cong-thuc-thu-nhap',102,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f3f607bc-3c04-4744-9a84-25b31b8c32c3','88a0c865-1202-45b2-9925-134c777f28ff',278,'image',NULL,'book/06-stars-luong-thuong/21fb25b0-eb53-406a-bbfc-bb8e20e19bc3-img16.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fb880edf-47ae-4a1e-a4bf-9b64ca734b60','88a0c865-1202-45b2-9925-134c777f28ff',279,'text','Trong đó:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a4a2f6f7-255d-47e0-8622-99283dfda61a','88a0c865-1202-45b2-9925-134c777f28ff',280,'text','- **Lương cố định** là phần thu nhập nền để đảm bảo sự ổn định và cam kết làm việc.- **Thu nhập theo case hoặc % doanh thu điều trị** là phần trả cho giá trị điều trị thực tế mà bác sĩ tạo ra; Finance OS cho phép ghi nhận chi phí bác sĩ theo ca hoặc theo phần trăm.- **Thưởng A.R** là phần thưởng theo hành động đúng và kết quả đo lường được, như tỷ lệ chấp nhận điều trị, hoàn tất điều trị, hồ sơ chuẩn, ít lỗi chuyên môn và case chất lượng.- **Thưởng Synergy** là phần thưởng cho đóng góp vào kết quả chung của toàn phòng khám, bao gồm phối hợp nội bộ, trải nghiệm khách hàng, review và referral.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('879adecc-8b1b-4629-938c-2bbc4516aac1','06-stars-luong-thuong','dc0f95e9-0163-4085-b35f-0ef092cb2361',4,'Trách nhiệm','trach-nhiem',103,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('67a80e34-9c72-44f1-8c59-e95c0983748f','879adecc-8b1b-4629-938c-2bbc4516aac1',281,'text','- Bác sĩ phải thực hiện đúng chuyên môn, đúng quy trình, đúng cam kết và không làm dư vì doanh thu ngắn hạn.- Bác sĩ cần đảm bảo hồ sơ đầy đủ, bàn giao rõ, phối hợp tốt với phụ tá, lễ tân, CSKH và Sales, đồng thời tuân thủ nguyên tắc Integrity là tử tế, chính trực, minh bạch, giữ lời và làm đúng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('fa6f0c76-d84c-4e6a-80e1-951f66cc797c','06-stars-luong-thuong','dc0f95e9-0163-4085-b35f-0ef092cb2361',4,'KPI đánh giá','kpi-anh-gia',104,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4c399aca-1848-4cb8-b8a0-82618eb68d14','fa6f0c76-d84c-4e6a-80e1-951f66cc797c',282,'text','KPI của bác sĩ tối thiểu gồm:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d53e1f41-c25a-47c2-8d8a-39e2e9419270','fa6f0c76-d84c-4e6a-80e1-951f66cc797c',283,'text','- Consultation completion.- Treatment acceptance rate.- Treatment completion rate.- Revenue per consultation.- Chất lượng hồ sơ.- Sự cố hoặc biến chứng chuyên môn.- Số case chất lượng.- Tỷ lệ phối hợp bàn giao tốt.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('6907f6ff-e9a6-4380-ae88-8a7c298d6821','06-stars-luong-thuong','dc0f95e9-0163-4085-b35f-0ef092cb2361',4,'Nguyên tắc thưởng','nguyen-tac-thuong',105,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2573d0f1-dd92-4b5e-8d9a-e9778bb943d4','6907f6ff-e9a6-4380-ae88-8a7c298d6821',284,'text','- Bác sĩ chỉ được thưởng trên kết quả được đo bằng số liệu và không thưởng cho kết quả tạo ra bằng hành vi sai ONE LIGHT như tư vấn sai sự thật, làm dư, ép khách hoặc chạy số bất chấp.- Nếu bác sĩ vừa tạo doanh thu, vừa đảm bảo chất lượng và phối hợp tốt thì mới được ghi nhận đầy đủ qua cả A.R và Synergy.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('83dd565e-ffdb-4231-a8a0-dad35f7c9578','06-stars-luong-thuong','dc0f95e9-0163-4085-b35f-0ef092cb2361',4,'Tiêu chuẩn đạt','tieu-chuan-at',106,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4c2ad6ca-6347-493c-9313-1732c600787c','83dd565e-ffdb-4231-a8a0-dad35f7c9578',285,'text','- Bác sĩ đạt chuẩn khi tạo ra kết quả chuyên môn tốt, hồ sơ rõ ràng, khách tin tưởng, điều trị hoàn tất đúng kế hoạch và phối hợp tốt với team.- Bác sĩ không đạt khi tư vấn thiếu trung thực, tỷ lệ hoàn tất thấp, hồ sơ kém, có lỗi chuyên môn lặp lại hoặc làm hỏng trải nghiệm tổng thể của khách hàng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('00a4696b-7c5e-4419-9a31-1e79bafd06b0','06-stars-luong-thuong','80177ac7-7d80-412d-9679-d3b1bc5fdb82',3,'14.2 Phụ tá','142-phu-ta',107,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('03e8c290-d351-4777-8836-34801f8bf997','06-stars-luong-thuong','00a4696b-7c5e-4419-9a31-1e79bafd06b0',4,'Định nghĩa','inh-nghia',108,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0bbf87ee-dc4c-4c81-aa64-61769d113de4','03e8c290-d351-4777-8836-34801f8bf997',286,'text','- Phụ tá nha khoa là vai trò hỗ trợ lâm sàng trong Clinical Circle, chịu trách nhiệm chuẩn bị dụng cụ, hỗ trợ bác sĩ trong ca điều trị, bảo đảm vô khuẩn, giữ quy trình trơn tru và hỗ trợ trải nghiệm bệnh nhân trong phòng điều trị.- Phụ tá được xem là một vai trò vận hành lâm sàng, với KPI trọng tâm là chuẩn bị phòng đúng, đủ vật tư, hỗ trợ ca mượt, tuân thủ vô khuẩn và báo thiếu vật tư kịp thời.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5260393c-e8a0-4bc4-9480-a3d354d1a23f','06-stars-luong-thuong','00a4696b-7c5e-4419-9a31-1e79bafd06b0',4,'Công thức thu nhập','cong-thuc-thu-nhap',109,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('de3d46bf-6674-4ad8-b4c3-20e8bf79a89d','5260393c-e8a0-4bc4-9480-a3d354d1a23f',287,'text','Giống Bác Sĩ nhưng tỉ lệ % trên doanh thu sẽ nhỏ hơn Bác sĩ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4f87cd6e-3a76-44d5-bd1c-df4e89a63ac3','5260393c-e8a0-4bc4-9480-a3d354d1a23f',288,'text','**Tổng thu nhập phụ tá = Lương cố định + % Doanh thu + Thưởng A.R + Thưởng Synergy**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fb549b5d-1290-490a-869c-22f7d9e6ea42','5260393c-e8a0-4bc4-9480-a3d354d1a23f',289,'text','Trong đó:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ee6d3741-b712-4d3b-8cbb-7df4923eda90','5260393c-e8a0-4bc4-9480-a3d354d1a23f',290,'text','- **Lương cố định** là phần thu nhập nền để giữ ổn định nhân sự và bảo đảm sự hiện diện đúng lịch.- **Thu nhập theo case hoặc % doanh thu điều trị** là phần trả cho giá trị điều trị thực tế mà bác sĩ tạo ra; Finance OS cho phép ghi nhận chi phí bác sĩ theo ca hoặc theo phần trăm.- **Thưởng A.R** là phần thưởng cho các hành động đúng và kết quả đo được như chuẩn bị phòng đúng giờ, đủ vật tư, hỗ trợ ca mượt, vô khuẩn đúng chuẩn và bàn giao ca tốt.- **Thưởng Synergy** là phần thưởng cho khả năng phối hợp với bác sĩ, lễ tân, CSKH và toàn bộ team điều trị, góp phần tạo kết quả chung của phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('dfa83ccf-3332-402a-ba2b-b38c6f44974e','06-stars-luong-thuong','00a4696b-7c5e-4419-9a31-1e79bafd06b0',4,'Trách nhiệm','trach-nhiem',110,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('77203f24-caff-40ef-989a-0cb3fd4b6174','dfa83ccf-3332-402a-ba2b-b38c6f44974e',291,'text','- Phụ tá phải chuẩn bị đầy đủ dụng cụ, hỗ trợ bác sĩ chính xác, tuân thủ vô khuẩn, giữ phòng điều trị sẵn sàng và báo cáo tình trạng vật tư hoặc sự cố kịp thời.- Phụ tá không chỉ làm việc “hỗ trợ”, mà còn là người giữ nhịp cho ca điều trị, giúp giảm lỗi vận hành và nâng trải nghiệm của bệnh nhân.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e152c99e-1b49-4b52-96be-1d354011368b','06-stars-luong-thuong','00a4696b-7c5e-4419-9a31-1e79bafd06b0',4,'KPI đánh giá','kpi-anh-gia',111,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('24e2ce3c-7950-430a-847e-4d9e5cac2c91','e152c99e-1b49-4b52-96be-1d354011368b',292,'text','KPI của phụ tá tối thiểu gồm:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1ef01921-aa34-4313-8051-a77b57dd7b4d','e152c99e-1b49-4b52-96be-1d354011368b',293,'text','- Chuẩn bị phòng đúng và đúng giờ.- Đủ vật tư cho ca điều trị.- Hỗ trợ ca mượt.- Tuân thủ vô khuẩn.- Bàn giao ca đúng chuẩn.- Tỷ lệ thiếu sót hoặc sai sót thấp.- Mức phối hợp tốt với bác sĩ và team.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1f32e0d6-dcdf-4b11-9372-86db0095a25c','06-stars-luong-thuong','00a4696b-7c5e-4419-9a31-1e79bafd06b0',4,'Nguyên tắc thưởng','nguyen-tac-thuong',112,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('012337f1-aa3b-442c-bd65-7a10409b12dd','1f32e0d6-dcdf-4b11-9372-86db0095a25c',294,'text','- Phụ tá chỉ được thưởng khi kết quả gắn với hành động cụ thể, đo được và phù hợp với nguyên tắc ONE LIGHT; không thưởng theo cảm tính hoặc vì “làm nhiều” nếu chất lượng thấp.- Nếu phụ tá làm tốt phần chuẩn bị, vô khuẩn, phối hợp và bàn giao, thì phần thưởng nên phản ánh đúng mức đóng góp vào hiệu suất của cả phòng khám, không tách rời khỏi kết quả chung.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f3425046-e431-43c7-a141-374a86a4b2ab','06-stars-luong-thuong','00a4696b-7c5e-4419-9a31-1e79bafd06b0',4,'Tiêu chuẩn đạt','tieu-chuan-at',113,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4759bebd-18a2-4634-80fc-bc8bf96c500c','f3425046-e431-43c7-a141-374a86a4b2ab',295,'text','- Phụ tá đạt chuẩn khi ca điều trị trôi chảy, vật tư đầy đủ, vô khuẩn đúng, bác sĩ làm việc thuận và bệnh nhân cảm thấy yên tâm, chuyên nghiệp.- Phụ tá không đạt khi thường xuyên thiếu vật tư, sai quy trình, hỗ trợ chậm, làm gián đoạn ca điều trị hoặc để phát sinh lỗi bàn giao lặp lại.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f458cc8d-47db-4759-8a72-f269c770d097','06-stars-luong-thuong','2b91b460-892a-4138-b284-483177963567',2,'Cơ chế lương thưởng theo nhóm vai trò','co-che-luong-thuong-theo-nhom-vai-tro',114,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('508eb5dd-d0dc-4459-a0fa-d18ab1dd7fd8','f458cc8d-47db-4759-8a72-f269c770d097',296,'text','- Cơ chế lương thưởng trong phòng khám được thiết kế theo nguyên tắc: **lương trả cho vai trò, thưởng trả cho kết quả, và tổng thu nhập phản ánh mức độ đóng góp thực tế của từng nhóm vai trò**.- Mỗi nhóm vai trò có cấu trúc lương thưởng khác nhau tùy theo đầu ra chính của nhóm đó, bảo đảm phù hợp với tính chất công việc, mức độ ảnh hưởng đến doanh thu, trải nghiệm khách hàng, hiệu quả vận hành và chất lượng hệ thống.- Việc thiết kế lương thưởng phải gắn với ONE LIGHT, không khuyến khích chạy số bất chấp, không thưởng cho kết quả tạo ra bằng hành vi sai chuẩn, và không dùng thưởng để thay thế cho trách nhiệm vận hành đúng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2762b638-160c-4267-8548-928234ef410e','06-stars-luong-thuong','2b91b460-892a-4138-b284-483177963567',2,'Quy trình 10 bước tính lương chuẩn','quy-trinh-10-buoc-tinh-luong-chuan',115,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('84b9f54b-9ad2-4bfc-9068-371d36600810','06-stars-luong-thuong','2762b638-160c-4267-8548-928234ef410e',3,'1) Xác định doanh thu','1-xac-inh-doanh-thu',116,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7f58e9c2-2c8e-4f10-b5db-1b67b961685d','84b9f54b-9ad2-4bfc-9068-371d36600810',297,'text','- Đây là bước ghi nhận tổng doanh thu trong kỳ theo ngày, tuần hoặc tháng. Doanh thu nên được tách theo nguồn hoặc dịch vụ để sau này phân bổ thưởng chính xác hơn.- **Công thức:** Tổng doanh thu = Tổng tiền thu trong kỳ.- **Ví dụ:** Tháng này phòng khám ghi nhận 500 triệu doanh thu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2d266428-dc8a-481d-8d31-cd580bea7e53','06-stars-luong-thuong','2762b638-160c-4267-8548-928234ef410e',3,'2) Trừ chi phí','2-tru-chi-phi',117,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5b016549-b455-4917-b2d6-4b3e54f845e2','2d266428-dc8a-481d-8d31-cd580bea7e53',298,'text','- Trừ toàn bộ chi phí cố định và biến đổi để xác định mức lợi nhuận thực. Chi phí nên gồm lương cứng, % doanh thu cho bác sĩ và phụ tá, mặt bằng, vật tư, lab, ads, phần mềm và các khoản vận hành liên quan.- **Công thức:** Tổng chi phí = Chi phí cố định + Chi phí biến đổi.- **Ví dụ:** Tổng chi phí tháng này là 320 triệu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0cb0e97f-3e3e-45e5-aad4-42f63b586865','06-stars-luong-thuong','2762b638-160c-4267-8548-928234ef410e',3,'3) Tính lợi nhuận','3-tinh-loi-nhuan',118,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5f925c67-075f-456e-8958-736f5655912a','0cb0e97f-3e3e-45e5-aad4-42f63b586865',299,'text','- Sau khi trừ chi phí, phòng khám xác định lợi nhuận gộp hoặc lợi nhuận vận hành. Đây là nền tảng để biết có thể trích thưởng hay không.- **Công thức:** Lợi nhuận = Doanh thu - Chi phí.- **Ví dụ:** 500 triệu - 320 triệu = 180 triệu lợi nhuận.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('20961c34-bc29-45bb-a173-7738e21462c8','06-stars-luong-thuong','2762b638-160c-4267-8548-928234ef410e',3,'4) Kiểm tra hòa vốn','4-kiem-tra-hoa-von',119,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0ad517d7-9fd5-4b42-8bfd-c2f45217008f','20961c34-bc29-45bb-a173-7738e21462c8',300,'text','- Bước này xác nhận phòng khám đã vượt ngưỡng hòa vốn chưa và còn bao nhiêu biên an toàn. Nếu chưa vượt hòa vốn, quỹ thưởng cần được siết lại để tránh ảnh hưởng dòng tiền.- **Công thức:** Biên an toàn = Lợi nhuận - Điểm hòa vốn.- **Ví dụ:** Điểm hòa vốn là 150 triệu, lợi nhuận là 180 triệu, nên còn 30 triệu biên an toàn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('06164fc4-f529-4956-ada3-1d8c691a5816','06-stars-luong-thuong','2762b638-160c-4267-8548-928234ef410e',3,'5) Tính quỹ thưởng','5-tinh-quy-thuong',120,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a516fe4b-5dba-4e94-855f-07313449ee1a','06164fc4-f529-4956-ada3-1d8c691a5816',301,'text','- Quỹ thưởng được xác định từ phần lợi nhuận khả dụng sau khi giữ lại một phần cho dự phòng và vận hành. Đây là bước để lương thưởng không vượt khả năng chi trả của hệ thống.- **Công thức:** Quỹ thưởng = Lợi nhuận khả dụng x Tỷ lệ thưởng.- **Ví dụ:** Nếu cho phép trích 20% từ 180 triệu thì quỹ thưởng là 36 triệu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('72c8522e-43b5-471f-8c89-2edc9d9a615d','06-stars-luong-thuong','2762b638-160c-4267-8548-928234ef410e',3,'6) Áp dụng CAP','6-ap-dung-cap',121,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('36bc677b-2bc5-446e-a7d2-9c6639ae5a14','72c8522e-43b5-471f-8c89-2edc9d9a615d',302,'text','- Cap là mức trần quỹ thưởng tối đa trong kỳ. Mục tiêu là bảo vệ biên lợi nhuận và tránh tình trạng tháng tốt trả thưởng quá tay, tháng xấu mất cân đối.- **Công thức:** Quỹ thưởng thực nhận = min(Quỹ thưởng tính được, Cap).- **Ví dụ:** Quỹ tính ra là 36 triệu nhưng cap là 30 triệu, thì quỹ thưởng thực nhận là 30 triệu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('35e860c8-5f15-42d0-bf5c-d348a62d1aed','06-stars-luong-thuong','2762b638-160c-4267-8548-928234ef410e',3,'7) Chia Circle','7-chia-circle',122,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7b1906ca-bc40-4b6c-bb40-b58d5a4478bb','35e860c8-5f15-42d0-bf5c-d348a62d1aed',303,'text','- Sau khi có quỹ thưởng tổng, phân bổ cho từng Circle theo đóng góp vào kết quả chung. Cách này phản ánh đúng tinh thần Synergy: kết quả chung là của cả hệ thống, không chỉ của một bộ phận.- **Công thức:** Quỹ Circle = Quỹ thưởng thực nhận x Tỷ lệ Circle.- **Ví dụ:** 30 triệu quỹ thưởng, trong đó Growth 30%, Patient 30%, Clinical 25%, Finance & Data 15%.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5261ba30-9c04-44f6-b778-6e7c939bfd66','06-stars-luong-thuong','2762b638-160c-4267-8548-928234ef410e',3,'8) Tính thưởng cá nhân','8-tinh-thuong-ca-nhan',123,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1db37a59-4e99-4249-b87c-cb569a7b75f2','5261ba30-9c04-44f6-b778-6e7c939bfd66',304,'text','- Trong mỗi Circle, tiếp tục chia theo Role Card, KPI và mức độ hoàn thành. Cách này giúp thưởng cá nhân bám vào đầu ra cụ thể thay vì chia cảm tính.- **Công thức:** Thưởng cá nhân = Quỹ Circle x Tỷ lệ role x Hệ số KPI.- **Ví dụ:** Một CSKH đạt 100% KPI có thể nhận toàn bộ mức thưởng role; người đạt 80% KPI nhận 80% phần đó.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('d7414d22-a968-473e-ba4f-bb843ec597b9','06-stars-luong-thuong','2762b638-160c-4267-8548-928234ef410e',3,'9) Cộng tổng thu nhập','9-cong-tong-thu-nhap',124,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2ee4e79b-2391-4098-87c6-59c1979f1c3d','d7414d22-a968-473e-ba4f-bb843ec597b9',305,'text','- Tổng thu nhập mỗi người bao gồm lương cứng, phụ cấp và các khoản thưởng liên quan. Đây là con số cuối cùng để trả lương trong kỳ.- **Công thức:** Tổng thu nhập = Lương cứng + Phụ cấp + Thưởng cá nhân + Thưởng Circle + Thưởng khác.- **Ví dụ:** Lương cứng 12 triệu + thưởng cá nhân 3 triệu + thưởng Circle 1 triệu = 16 triệu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('45752546-79de-4b04-bb38-8f279030ae71','06-stars-luong-thuong','2762b638-160c-4267-8548-928234ef410e',3,'10) Chốt lợi nhuận sau thưởng','10-chot-loi-nhuan-sau-thuong',125,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('65cbb0ae-b3be-4b96-bb01-674d22e12a9a','45752546-79de-4b04-bb38-8f279030ae71',306,'text','- Sau khi cộng toàn bộ tiền thưởng, phòng khám chốt lại lợi nhuận còn lại để kiểm tra mức an toàn tài chính. Đây là bước bắt buộc để xác nhận mô hình lương thưởng vẫn bền vững.- **Công thức:** Lợi nhuận sau thưởng = Lợi nhuận trước thưởng - Tổng quỹ thưởng đã chi.- **Ví dụ:** 180 triệu lợi nhuận - 30 triệu quỹ thưởng = 150 triệu lợi nhuận sau thưởng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('4347c8b4-468a-4e92-a508-0104b7097848','06-stars-luong-thuong','2762b638-160c-4267-8548-928234ef410e',3,'Ghi chú vận hành','ghi-chu-van-hanh',126,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c4aea13c-26b8-489a-8fa8-8428f4deafe2','4347c8b4-468a-4e92-a508-0104b7097848',307,'text','- Quy trình này nên được áp dụng theo tháng, nhưng dữ liệu đầu vào phải được cập nhật đều theo ngày và tuần để tránh lệch số.- Mỗi bước nên gắn với một owner rõ trong Finance / People / Data OS, đặc biệt là Finance Owner, Data Owner và People Owner',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ee2c9f09-6d8a-4b05-82ef-df3e741add2e','06-stars-luong-thuong','2b91b460-892a-4138-b284-483177963567',2,'Nguyên lý vận hành cốt lõi','nguyen-ly-van-hanh-cot-loi',127,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a948dbf8-533e-4f23-82db-cdac745dc383','ee2c9f09-6d8a-4b05-82ef-df3e741add2e',308,'image',NULL,'book/06-stars-luong-thuong/3bc93375-40d5-441d-8f47-0aa1eb61805b-img17.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('81354f26-cef0-4cfd-bc98-08dc5dc6ef05','06-stars-luong-thuong',NULL,1,'SO SÁNH VỚI MÔ HÌNH LƯƠNG 3Ps','so-sanh-voi-mo-hinh-luong-3ps',128,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('40bac070-2552-479c-abb4-796775d5732c','81354f26-cef0-4cfd-bc98-08dc5dc6ef05',309,'text','Tài liệu này chuẩn hóa cách thiết kế lương thưởng theo 3 lớp: **3P** để định giá nền, **STARS** để quản trị con người, và **mô hình 10 bước** để chốt quỹ thưởng theo số liệu thực tế.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('dc62bd39-a215-44d5-b116-6918182d2a84','06-stars-luong-thuong','81354f26-cef0-4cfd-bc98-08dc5dc6ef05',2,'Mục đích sử dụng','muc-ich-su-dung',129,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('aff9dcee-d8f6-4638-9453-f469f13bc6ac','dc62bd39-a215-44d5-b116-6918182d2a84',310,'text','Ba mô hình không thay thế nhau mà bổ sung cho nhau trong cùng một hệ thống. 3P trả lời câu hỏi “trả lương theo cái gì”, STARS trả lời “quản trị con người như thế nào”, còn mô hình 10 bước trả lời “cuối kỳ tính và chia lương thưởng ra sao”.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('6b390814-e576-4948-b459-5b3ce409dcbc','06-stars-luong-thuong','81354f26-cef0-4cfd-bc98-08dc5dc6ef05',2,'Bảng handbook','bang-handbook',130,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8508c069-0b1e-4c8c-a665-bab6a0e5aa3f','6b390814-e576-4948-b459-5b3ce409dcbc',311,'image',NULL,'book/06-stars-luong-thuong/5cd5846c-ebb2-40a3-b1ac-1b2c3b049acb-img18.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('68b20c4c-edfd-40ee-b1df-0aff14f1c326','06-stars-luong-thuong','81354f26-cef0-4cfd-bc98-08dc5dc6ef05',2,'Công thức chuẩn','cong-thuc-chuan',131,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('c15ab26e-00ac-466c-91ef-d507ccfb3d14','06-stars-luong-thuong','68b20c4c-edfd-40ee-b1df-0aff14f1c326',3,'3P','3p',132,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1dd381a8-f912-46c8-aa12-4b34766b6704','c15ab26e-00ac-466c-91ef-d507ccfb3d14',312,'text','- Công thức tổng quát của 3P là:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b61c3bcd-e4c1-400d-874d-04993722d64b','c15ab26e-00ac-466c-91ef-d507ccfb3d14',313,'text','**Tổng thu nhập = Lương theo vị trí + Phụ cấp theo năng lực + Thưởng theo hiệu quả**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4d65fc96-c483-4d44-a887-bd54c3f5708d','c15ab26e-00ac-466c-91ef-d507ccfb3d14',314,'text','- *Ví dụ ngắn: *một lễ tân có lương vị trí 8 triệu, phụ cấp 1 triệu, thưởng hiệu suất 2 triệu thì tổng thu nhập là 11 triệu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('6551d13e-8245-44de-80b0-5967792de1bb','06-stars-luong-thuong','68b20c4c-edfd-40ee-b1df-0aff14f1c326',3,'STARS','stars',133,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2d9200fc-60ca-4ca0-9d1b-cd5a3706761c','6551d13e-8245-44de-80b0-5967792de1bb',315,'text','- Công thức lõi của STARS là:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0d9b8788-9e49-4814-b980-fd541995d862','6551d13e-8245-44de-80b0-5967792de1bb',316,'text','**S.T.A.R.S People OS = Role rõ + Năng lực rõ + Checklist rõ + KPI rõ + Lương thưởng rõ + Văn hóa rõ**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('339b6528-3314-45b6-9869-dbabc29f5ee5','6551d13e-8245-44de-80b0-5967792de1bb',317,'text','- Ngoài ra, mô hình còn nhấn mạnh ONE LIGHT** = Tử tế + Chính trực + Minh bạch + Giữ lời + Làm đúng**.- Thưởng trong STARS thường tách thành **Thưởng A.R = Thưởng hành động đúng + Thưởng kết quả đạt + Thưởng hiệu quả tốt + Thưởng cải tiến hệ thống**.- Ví dụ ngắn: một CSKH hoàn thành follow-up đúng hạn, tăng tái khám và hỗ trợ xin review đúng lúc có thể nhận thưởng cá nhân và thưởng synergy của đội.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('92ce5c4f-7ce3-403a-bc53-48b0fb4b24c8','06-stars-luong-thuong','68b20c4c-edfd-40ee-b1df-0aff14f1c326',3,'Checklist','checklist',134,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('305a4c8f-25dd-4588-b0b9-946b07323e66','92ce5c4f-7ce3-403a-bc53-48b0fb4b24c8',318,'text','- Đã có mô tả rõ Position, Person, Performance cho từng vai trò.- Đã có Role Card cho từng vị trí chính.- Đã gắn mỗi role với KPI và checklist cụ thể.- Đã có công thức lương cứng, phụ cấp và thưởng cá nhân.- Đã có tiêu chí thưởng A.R và thưởng synergy.- Đã có P&L hoặc dashboard để xác định quỹ thưởng hợp lệ.- Đã có cap quỹ thưởng để bảo vệ dòng tiền.- Đã có lịch review tuần/tháng/quý cho role và KPI',NULL,NULL,NULL,NULL,NULL);
